                              <el-tag
                                v-for="risk in item.audit.risk_signals"
                                :key="`risk-${risk.id}-${risk.snippet}`"
                                size="small"
                                type="danger"
                                effect="plain"
                              >
                                {{ risk.label }}
                              </el-tag>
                            </div>
                          </div>
                          <div class="message-audit-section">
                            <div class="message-audit-label">工作区变更</div>
