                              <pre
                                v-if="item.audit.after_diff_summary.diff_stat"
                                class="message-audit-pre"
                                >{{
                                  item.audit.after_diff_summary.diff_stat
                                }}</pre
                              >
                              <pre
                                v-else-if="
                                  item.audit.after_diff_summary.status_lines
                                    ?.length
                                "
                                class="message-audit-pre"
                                >{{
                                  item.audit.after_diff_summary.status_lines.join(
                                    "\n",
