                                    getTaskTreeAuditSeverityMeta(
                                      item.taskTreeAudit.severity,
                                    ).label
                                  }}
                                </el-tag>
                                <el-tag
                                  v-if="item.taskTreeAudit.category"
                                  size="small"
                                  effect="plain"
