                            :loading="
                              aiContextDialogLoading &&
                              aiContextDialogMessageId ===
                                String(item.id || '').trim()
                            "
                            @click="openAiRequestContextDialog(item)"
                          >
                            查看上下文
                          </el-button>
                        </div>
