                        >
                          <el-button
                            text
                            size="small"
                            class="message-action-button"
                            :icon="action.icon"
                            circle
                            @click="handleMessageAction(item, idx, action.key)"
                          />
                        </el-tooltip>
                      </div>
                    </div>
                  </div>
