  <UnifiedMcpAccessDialog
    v-model="unifiedMcpDialogVisible"
    title="统一 MCP 接入"
    :project-id="mcpDialogProjectId"
    :project-label="mcpDialogProjectLabel"
    :chat-session-id="currentChatSessionId"
  />

  <el-dialog
    v-model="mcpServerDialogVisible"
    :title="mcpServerDialogTitle"
    width="min(720px, 92vw)"
    append-to-body
  >
    <el-form label-position="top" class="mcp-server-form">
      <el-form-item label="作用域">
        <el-segmented
          v-model="mcpServerScope"
          :options="mcpScopeOptions"
          :disabled="mcpServerDialogMode === 'edit'"
        />
        <div class="mcp-form-hint">
          不确定时直接粘贴完整 JSON，系统会自动识别 stdio / HTTP / SSE。
        </div>
      </el-form-item>
      <el-form-item label="Server 名称">
        <el-input
          v-model="mcpServerDraft.name"
          placeholder="query-center"
          :disabled="mcpServerDialogMode === 'edit'"
        />
      </el-form-item>
      <el-form-item label="传输类型">
        <el-segmented v-model="mcpServerDraft.type" :options="mcpTransportOptions" />
      </el-form-item>
      <el-form-item
        v-if="mcpServerDraft.type === 'stdio'"
        label="命令"
      >
        <el-input v-model="mcpServerDraft.command" placeholder="/usr/local/bin/my-mcp" />
      </el-form-item>
      <el-form-item
        v-if="mcpServerDraft.type === 'stdio'"
        label="参数"
      >
        <el-input
          v-model="mcpServerDraft.argsText"
          placeholder='["--stdio"]'
        />
      </el-form-item>
      <el-form-item
        v-if="mcpServerDraft.type === 'stdio'"
        label="工作目录"
      >
        <el-input
          v-model="mcpServerDraft.cwd"
          placeholder=". 或 /path/to/server"
        />
      </el-form-item>
      <el-form-item
        v-if="mcpServerDraft.type !== 'stdio'"
        label="URL"
      >
        <el-input
          v-model="mcpServerDraft.url"
          placeholder="http://127.0.0.1:8000/mcp/query/sse"
        />
      </el-form-item>
      <el-form-item label="请求头 JSON">
        <el-input
          v-model="mcpServerDraft.headersText"
          type="textarea"
          :rows="3"
          placeholder='{"Authorization":"Bearer ..."}'
        />
      </el-form-item>
      <el-form-item>
        <el-checkbox v-model="mcpServerDraft.enabled">启用</el-checkbox>
      </el-form-item>
      <el-form-item label="完整 JSON 配置">
        <el-input
          v-model="mcpServerDraft.rawJsonText"
          type="textarea"
          :rows="8"
          resize="vertical"
          spellcheck="false"
          placeholder='{"command":"npx","args":["ace-tool","--base-url","https://...","--token","..."]}'
        />
        <div class="mcp-form-hint">
          测试和保存会优先使用这里的完整 JSON；无需先点击导入。
        </div>
        <div class="mcp-local-editor__actions">
          <el-button size="small" @click="applyMcpServerRawJson">
            导入 JSON
          </el-button>
        </div>
      </el-form-item>
    </el-form>
    <template #footer>
      <el-button @click="mcpServerDialogVisible = false">取消</el-button>
      <el-button :loading="mcpServerTesting" @click="testMcpServerDraft">
        测试
      </el-button>
      <el-button type="primary" @click="saveMcpServerDraft">
        保存
      </el-button>
    </template>
  </el-dialog>

  <el-dialog
    v-model="webToolsProviderDialogVisible"
    :title="webToolsProviderDialogTitle"
    width="min(640px, 92vw)"
    append-to-body
  >
    <el-form label-position="top" class="web-tools-provider-form">
      <el-form-item label="作用域">
        <el-segmented
          v-model="webToolsProviderDialogScope"
          :options="webToolsScopeOptions"
        />
      </el-form-item>
      <el-form-item>
        <el-checkbox v-model="webToolsProviderDraft.enabled">
          设为当前作用域默认搜索后端
        </el-checkbox>
      </el-form-item>
      <el-form-item
        v-for="field in webToolsProviderDialogFieldRows"
        :key="field.key"
        :label="field.label"
      >
        <el-input
          v-model="webToolsProviderDraft.fields[field.key]"
          :type="field.secret ? 'password' : 'text'"
          :show-password="field.secret"
          :placeholder="field.placeholder"
        />
      </el-form-item>
    </el-form>
    <template #footer>
      <el-button @click="webToolsProviderDialogVisible = false">取消</el-button>
      <el-button type="primary" @click="saveWebToolsProviderDraft">
        保存
      </el-button>
    </template>
  </el-dialog>

  <CodePreviewDialog
    v-model="codePreviewVisible"
    :title="codePreviewTitle"
    :srcdoc="codePreviewSrcdoc"
    :error="codePreviewError"
  />

  <el-dialog
    v-model="aiContextDialogVisible"
    title="发送给 AI 的上下文"
    width="min(960px, 92vw)"
    class="ai-context-dialog"
    append-to-body
  >
    <div class="ai-context-dialog__body" v-loading="aiContextDialogLoading">
      <el-alert
        v-if="aiContextDialogError"
        :title="aiContextDialogError"
        type="error"
        show-icon
        :closable="false"
      />
      <template v-else>
        <div class="ai-context-dialog__summary">
          <span>
            {{ aiContextDialogProviderLabel }}
          </span>
          <span>
            消息 {{ aiContextDialogMessageId || "-" }}
          </span>
        </div>
        <pre class="ai-context-dialog__pre">{{
          formattedAiContextDialogPayload
        }}</pre>
      </template>
    </div>
    <template #footer>
      <el-button @click="aiContextDialogVisible = false">关闭</el-button>
      <el-button
        type="primary"
        :disabled="!aiContextDialogPayload"
        @click="copyAiRequestContext"
      >
        复制 JSON
      </el-button>
    </template>
  </el-dialog>

  <ProjectEmployeeDraftCreateDialog
    v-model="employeeDraftDialogVisible"
    :loading="employeeDraftDialogLoading"
    :submitting="employeeCreateSubmitting"
    :payload="employeeDraftDialogPayload"
    :matched-skill-labels="employeeDraftDialogMatchedSkillLabels"
    :matched-rule-labels="employeeDraftDialogMatchedRuleLabels"
    :rule-draft-labels="employeeDraftDialogRuleDraftLabels"
    :auto-rule-generation-enabled="employeeDraftAutoRuleGenerationEnabled"
    :auto-rule-generation-max-count="employeeDraftAutoRuleGenerationMaxCount"
    :auto-rule-source-labels="employeeDraftAutoRuleSourceLabels"
    :can-add-to-project="Boolean(String(selectedProjectId || '').trim())"
    @confirm="confirmEmployeeDraftCreation"
    @close="resetEmployeeDraftDialogState"
  />

  <SkillResourceDialog
    v-model="skillResourceDialogVisible"
    v-model:search-query="skillResourceSearchQuery"
    :workspace-path-resolved="workspacePathResolved"
    :directory-resolved="skillResourceDirectoryResolved"
    :directory-picking="skillResourceDirectoryPicking"
    :search-loading="skillResourceSearchLoading"
    :search-results="skillResourceSearchResults"
    :resolved-queries="skillResourceSearchResolvedQueries"
    :sites="skillResourceSites"
    :installing-slug="skillResourceInstallingSlug"
    @use-workspace="useWorkspaceAsSkillDirectory"
    @pick-directory="pickSkillResourceDirectory"
    @copy-directory="copySkillResourceDirectory"
    @search="searchSkillResources"
    @reset-search="resetSkillResourceSearch"
    @install-site="installSkillResource"
    @copy-site="copySkillResourceSite"
  />

  <div
    v-if="isSettingsCenterRoute"
    class="settings-center-page"
    v-loading="loading"
  >
    <div
      class="settings-center-shell"
      :class="{
        'settings-center-shell--single': settingsInternalItems.length <= 1,
      }"
    >
      <aside
        v-if="settingsInternalItems.length > 1"
        class="settings-center-sidebar"
        ref="settingsSidebarRef"
      >
        <div class="settings-center-sidebar-card">
          <div class="settings-center-brand-panel">
            <div class="settings-center-brand">
              <div class="settings-center-brand__mark">AI</div>
              <div>
                <div class="settings-center-brand__name">对话设置</div>
                <div class="settings-center-brand__meta">
                  仅作用于当前对话上下文
                </div>
              </div>
            </div>
            <el-button
              text
              class="settings-center-close-button"
              @click="closeSettingsCenter"
              >关闭</el-button
            >
          </div>

          <div class="settings-center-nav-group">
            <div class="settings-center-nav-group__title">当前对话</div>
            <div class="settings-center-sidebar__nav">
              <button
                v-for="item in settingsInternalItems"
                :key="item.id"
                type="button"
                class="settings-center-nav-item"
                :class="{ 'is-active': activeSettingsPanel === item.id }"
                @click="openSettingsCenter(item.id)"
              >
                <span class="settings-center-nav-item__row">
                  <span class="settings-center-nav-item__label">{{
                    item.label
                  }}</span>
                </span>
                <span v-if="item.desc" class="settings-center-nav-item__desc">
                  {{ item.desc }}
                </span>
              </button>
            </div>
          </div>

          <div class="settings-center-account">
            <div class="settings-center-account__avatar">
              {{ currentUsernameInitial }}
            </div>
            <div class="settings-center-account__meta">
              <div class="settings-center-account__name">
                {{ currentUsername }}
              </div>
              <div class="settings-center-account__role">当前账号</div>
            </div>
            <el-button
              text
              class="settings-center-account__logout"
              @click="logoutFromChat"
              >退出</el-button
            >
          </div>
        </div>
      </aside>

      <section
        class="settings-center-stage"
        :class="{
          'settings-center-stage--single': settingsInternalItems.length <= 1,
        }"
      >
        <div class="settings-center-context-bar" ref="settingsContextBarRef">
          <div class="settings-center-context-bar__copy">
            <div class="settings-center-context-bar__title">
              {{ activeSettingsPanelMeta?.label || "设置" }}
            </div>
          </div>
          <div class="settings-center-context-bar__actions">
            <el-button
              v-if="settingsInternalItems.length > 1"
              type="primary"
              plain
              @click="startSettingsTour(true)"
              ref="settingsGuideButtonRef"
            >
              菜单导览
            </el-button>
            <el-button
              plain
              :loading="settingsSaving"
              @click="saveProjectChatSettings(false)"
            >
              立即同步
            </el-button>
            <el-button text @click="closeSettingsCenter">关闭</el-button>
          </div>
        </div>

        <div
          v-if="activeSettingsPanel === 'chat'"
          class="settings-center-stage__body settings-center-stage__body--chat"
        >
          <div class="settings-chat-layout settings-chat-layout--single">
            <div class="settings-chat-main settings-chat-main--wide">
              <div class="settings-chat-main-card" ref="settingsMainCardRef">
                <section class="settings-chat-quick-overview">
                  <article class="settings-chat-quick-overview__card">
                    <span class="settings-chat-quick-overview__label">
                      项目上下文
                    </span>
                    <strong class="settings-chat-quick-overview__value">{{
                      hasSelectedProject ? currentProjectLabel : "未选择项目"
                    }}</strong>
                    <span class="settings-chat-quick-overview__meta">
                      {{
                        hasSelectedProject
                          ? "当前改动只影响这个项目下的对话"
                          : "当前仅维护通用对话行为"
                      }}
                    </span>
                  </article>
                  <article class="settings-chat-quick-overview__card">
                    <span class="settings-chat-quick-overview__label">
                      执行对象
                    </span>
                    <strong class="settings-chat-quick-overview__value">{{
                      selectedEmployeeSummary
                    }}</strong>
                    <span class="settings-chat-quick-overview__meta">
                      {{
                        projectChatSettings.employee_coordination_mode ===
                        "manual"
                          ? "手动保留当前工具池"
                          : "允许系统自动协作"
                      }}
                    </span>
                  </article>
                  <article class="settings-chat-quick-overview__card">
                    <span class="settings-chat-quick-overview__label">
                      当前模型
                    </span>
                    <strong class="settings-chat-quick-overview__value">{{
                      currentModelTypeLabel
                    }}</strong>
                    <span class="settings-chat-quick-overview__meta">
                      {{ currentModelSummary }}
                    </span>
                  </article>
                  <article class="settings-chat-quick-overview__card">
                    <span class="settings-chat-quick-overview__label">
                      工具与 MCP
                    </span>
                    <strong class="settings-chat-quick-overview__value">{{
                      singleRoundAnswerOnly
                        ? "本轮仅回答"
                        : projectChatSettings.auto_use_tools
                          ? "允许工具调用"
                          : "关闭工具调用"
                    }}</strong>
                    <span class="settings-chat-quick-overview__meta">
                      {{
                        projectToolModules.length
                          ? `项目工具 ${selectedProjectToolNames.length}/${projectToolModules.length}`
                          : "当前没有项目级工具"
                      }}
                    </span>
                  </article>
                </section>

                <section class="settings-module-toolbar">
                  <el-input
                    v-model="settingsModuleSearchQuery"
                    clearable
                    placeholder="搜索设置、工具、MCP、模型参数"
                    class="settings-module-toolbar__search"
                  />
                  <el-segmented
                    v-model="settingsModuleScope"
                    :options="settingsModuleScopeOptions"
                    class="settings-module-toolbar__scope"
                  />
                </section>

                <div class="settings-module-workspace">
                  <aside class="settings-module-menu" aria-label="对话设置模块">
                    <button
                      v-for="item in visibleSettingsModuleNavItems"
                      :key="item.id"
                      type="button"
                      class="settings-module-menu__item"
                      :class="{ 'is-active': activeSettingsModule === item.id }"
                      @click="activeSettingsModule = item.id"
                    >
                      <span class="settings-module-menu__title">
                        {{ item.label }}
                      </span>
                      <span class="settings-module-menu__desc">
                        {{ item.desc }}
                      </span>
                      <span class="settings-module-menu__meta">
                        {{ item.meta }}
                      </span>
                    </button>
                    <el-empty
                      v-if="!visibleSettingsModuleNavItems.length"
                      description="没有匹配的设置模块"
                      :image-size="42"
                    />
                  </aside>

                  <div class="settings-module-list">
                  <section
                    v-show="
                      activeSettingsModule === 'context' &&
                      settingsModuleMatches('项目 上下文 工作区 AIENTRY 入口 文件 workspace ai entry', 'project')
                    "
                    class="settings-module-section"
                  >
                    <div class="settings-module-section__head">
                      <div>
                        <strong>项目上下文</strong>
                        <span>工作区和入口文件决定桌面智能体在本机如何理解项目。</span>
                      </div>
                    </div>
                    <article
                      v-if="hasSelectedProject"
                      class="settings-module-row settings-module-row--stacked"
                    >
                      <div class="settings-module-row__icon">
                        <el-icon><Files /></el-icon>
                      </div>
                      <div class="settings-module-row__main">
                        <strong>项目工作区</strong>
                        <span>本机真实目录；命令执行和相对路径解析会以这里为基准。</span>
                        <el-input
                          v-model="projectWorkspaceDraft"
                          class="settings-module-row__input"
                          placeholder="/Volumes/work/project"
                        />
                        <div class="settings-module-row__hint">
                          <template v-if="projectWorkspaceResolved">
                            已保存：{{ projectWorkspaceResolved }}
                          </template>
                          <template v-else>
                            当前项目还没有配置工作区路径。
                          </template>
                          <template v-if="projectWorkspaceDirty">
                            当前输入尚未保存。
                          </template>
                        </div>
                      </div>
                      <div class="settings-module-row__actions">
                        <el-button
                          @click="promptProjectWorkspaceDirectory"
                          :loading="projectWorkspacePicking"
                        >
                          选择目录
                        </el-button>
                        <el-button
                          type="primary"
                          :loading="projectWorkspaceSaving"
                          @click="saveProjectWorkspaceDirectory()"
                        >
                          保存
                        </el-button>
                      </div>
                    </article>
                    <article
                      v-if="hasSelectedProject"
                      class="settings-module-row settings-module-row--stacked"
                    >
                      <div class="settings-module-row__icon">
                        <el-icon><DocumentCopy /></el-icon>
                      </div>
                      <div class="settings-module-row__main">
                        <strong>AI 入口文件</strong>
                        <span>项目级规则入口；未设置时继续使用内置统一入口。</span>
                        <el-input
                          v-model="aiEntryFileDraft"
                          class="settings-module-row__input"
                          placeholder="AIENTRY.md"
                        />
                        <div class="settings-module-row__hint">
                          <template v-if="aiEntryFileResolved">
                            已保存：{{ aiEntryFileResolved }}
                          </template>
                          <template v-if="aiEntryFileDirty">
                            当前输入尚未保存。
                          </template>
                        </div>
                      </div>
                      <div class="settings-module-row__actions">
                        <el-button
                          @click="promptProjectAiEntryFile"
                          :loading="aiEntryFilePicking"
                        >
                          选择文件
                        </el-button>
                        <el-button
                          :loading="aiEntryFileCreating"
                          @click="createDefaultAiEntryFile"
                        >
                          创建
                        </el-button>
                        <el-button
                          type="primary"
                          :loading="aiEntryFileSaving"
                          @click="saveProjectAiEntryFile()"
                        >
                          保存
                        </el-button>
                      </div>
                    </article>
                    <article v-else class="settings-module-row">
                      <div class="settings-module-row__icon">
                        <el-icon><InfoFilled /></el-icon>
                      </div>
                      <div class="settings-module-row__main">
                        <strong>尚未选择项目</strong>
                        <span>选择项目后才能配置项目工作区和入口文件。</span>
                      </div>
                    </article>
                  </section>

                  <section
                    v-show="
                      activeSettingsModule === 'execution' &&
                      settingsModuleMatches('执行 员工 协作 模式 历史 消息 本轮 仅回答', 'project')
                    "
                    class="settings-module-section"
                  >
                    <div class="settings-module-section__head">
                      <div>
                        <strong>执行策略</strong>
                        <span>控制本轮对话如何分配员工、使用历史和选择工具边界。</span>
                      </div>
                    </div>
                    <article class="settings-module-row">
                      <div class="settings-module-row__icon">
                        <el-icon><CollectionTag /></el-icon>
                      </div>
                      <div class="settings-module-row__main">
                        <strong>执行员工</strong>
                        <span>{{ selectedEmployeeSummary }}</span>
                      </div>
                      <div class="settings-module-row__control">
                        <el-select
                          v-model="selectedEmployeeIds"
                          multiple
                          collapse-tags
                          collapse-tags-tooltip
                          filterable
                          clearable
                          placeholder="留空自动分配"
                          class="settings-module-row__select"
                          :disabled="!selectedProjectId"
                        >
                          <el-option
                            v-for="item in projectEmployees"
                            :key="item.id"
                            :label="`${item.name || item.id}`"
                            :value="item.id"
                          />
                        </el-select>
                      </div>
                    </article>
                    <article class="settings-module-row">
                      <div class="settings-module-row__icon">
                        <el-icon><CircleCheck /></el-icon>
                      </div>
                      <div class="settings-module-row__main">
                        <strong>协作模式</strong>
                        <span>决定员工如何分工；当前对话统一使用系统模型执行。</span>
                      </div>
                      <div class="settings-module-row__control">
                        <el-select
                          v-model="projectChatSettings.employee_coordination_mode"
                          class="settings-module-row__select"
                          :disabled="!selectedProjectId"
                        >
                          <el-option label="自动协作" value="auto" />
                          <el-option label="手动模式" value="manual" />
                        </el-select>
                      </div>
                    </article>
                    <article class="settings-module-row">
                      <div class="settings-module-row__icon">
                        <el-icon><EditPen /></el-icon>
                      </div>
                      <div class="settings-module-row__main">
                        <strong>历史消息条数</strong>
                        <span>控制发送给模型的上下文消息数量。</span>
                      </div>
                      <div class="settings-module-row__control">
                        <el-input-number
                          v-model="projectChatSettings.history_limit"
                          :min="1"
                          :max="50"
                        />
                      </div>
                    </article>
                    <article class="settings-module-row">
                      <div class="settings-module-row__icon">
                        <el-icon><InfoFilled /></el-icon>
                      </div>
                      <div class="settings-module-row__main">
                        <strong>单轮仅回答</strong>
                        <span>只对下一次对话生效，不主动调用工具。</span>
                      </div>
                      <el-switch v-model="singleRoundAnswerOnly" />
                    </article>
                  </section>

                  <section
                    v-show="
                      activeSettingsModule === 'generation' &&
                      settingsModuleMatches('生成 回答 模型 温度 风格 图片 视频 参数 结论', 'all')
                    "
                    class="settings-module-section"
                  >
                    <div class="settings-module-section__head">
                      <div>
                        <strong>生成回答</strong>
                        <span>当前模型类型：{{ currentModelTypeLabel }}。{{ currentModelTypeDescription || "参数面板会跟随当前模型类型切换。" }}</span>
                      </div>
                    </div>
                    <template v-if="currentModelParameterMode === 'text'">
                      <article class="settings-module-row">
                        <div class="settings-module-row__icon">
                          <el-icon><EditPen /></el-icon>
                        </div>
                        <div class="settings-module-row__main">
                          <strong>回答风格</strong>
                          <span>偏好 AI 返回内容的详细程度。</span>
                        </div>
                        <div class="settings-module-row__control">
                          <el-select
                            v-model="projectChatSettings.answer_style"
                            class="settings-module-row__select"
                          >
                            <el-option label="简洁" value="concise" />
                            <el-option label="平衡" value="balanced" />
                            <el-option label="详细" value="detailed" />
                          </el-select>
                        </div>
                      </article>
                      <article class="settings-module-row settings-module-row--stacked">
                        <div class="settings-module-row__icon">
                          <el-icon><RefreshRight /></el-icon>
                        </div>
                        <div class="settings-module-row__main">
                          <strong>温度</strong>
                          <span>值越小越稳，值越大越发散。</span>
                          <el-slider
                            v-model="temperature"
                            :min="0"
                            :max="2"
                            :step="0.1"
                            show-input
                            :show-input-controls="false"
                          />
                        </div>
                      </article>
                      <article class="settings-module-row">
                        <div class="settings-module-row__icon">
                          <el-icon><CircleCheck /></el-icon>
                        </div>
                        <div class="settings-module-row__main">
                          <strong>先结论后步骤</strong>
                          <span>长回答优先给出核心结论。</span>
                        </div>
                        <el-switch
                          v-model="projectChatSettings.prefer_conclusion_first"
                        />
                      </article>
                    </template>
                    <template
                      v-else-if="
                        currentModelParameterMode === 'image' ||
