  return value ? value.slice(0, 8) : "";
});
function isTerminalInputCandidateRow(row) {
  if (!row || String(row.role || "assistant") !== "assistant") return false;
  const terminalOperations = (
    Array.isArray(row.operations) ? row.operations : []
  ).filter(
    (operation) =>
      String(operation?.kind || "")
        .trim()
        .toLowerCase() === "terminal",
  );
  if (terminalOperations.length) {
    return terminalOperations.some((operation) => {
      const phase = normalizeOperationPhase(
        operation?.phase || operation?.status,
      );
      return !["completed", "failed", "blocked"].includes(phase);
    });
  }
  return (
    String(row.displayMode || "").trim() === "terminal" &&
    terminalPanelStatus.value === "running"
  );
}

function completeTerminalInputOperations(row, summary = "终端交互已结束") {
  if (!row || !Array.isArray(row.operations) || !row.operations.length)
    return false;
  let changed = false;
  row.operations = row.operations.map((operation) => {
    const kind = String(operation?.kind || "")
      .trim()
      .toLowerCase();
    if (kind !== "terminal") return operation;
    const phase = normalizeOperationPhase(
      operation?.phase || operation?.status,
    );
    if (["completed", "failed", "blocked"].includes(phase)) return operation;
    changed = true;
    return {
      ...operation,
      phase: "completed",
      summary: String(operation?.summary || summary).trim() || summary,
    };
  });
  return changed;
}

function completeFinishedMessageOperations(row, summary = "本轮执行已结束") {
  if (!row || !Array.isArray(row.operations) || !row.operations.length) {
    return false;
  }
  const finalSummary = String(summary || "").trim() || "本轮执行已结束";
  let changed = false;
  row.operations = row.operations.map((operation) => {
    const phase = normalizeOperationPhase(
      operation?.phase || operation?.status,
    );
    if (!["running", "pending"].includes(phase)) {
      return operation;
    }
    changed = true;
    return {
      ...operation,
      phase: "completed",
      actionType: "none",
      summary: String(operation?.summary || "").trim() || finalSummary,
      updatedAt: nowText(),
    };
  });
  return changed;
}

function isLiveTerminalOperation(operation) {
  const kind = String(operation?.kind || "")
    .trim()
    .toLowerCase();
  if (kind !== "terminal") return false;
  const phase = normalizeOperationPhase(operation?.phase || operation?.status);
  return !["completed", "failed", "blocked"].includes(phase);
}

function isLocalLiuAgentBubbleOnlyOperation(operation) {
  if (!operation || typeof operation !== "object") return false;
  const meta =
    operation.meta && typeof operation.meta === "object" ? operation.meta : {};
  if (String(meta.local_liuagent_permission || "").trim() === "true") {
    return true;
  }
  if (String(meta.local_liuagent_operation || "").trim() === "true") {
    return true;
  }
  if (String(meta.source || "").trim() === "tauri_liuagent_local_chat") {
    return true;
  }
  const operationId = String(
    operation.operationId || operation.id || "",
  ).trim();
  return (
    operationId.startsWith("local-agent:") ||
    operationId.startsWith("desktop-tool:") ||
    operationId.startsWith("local-liuagent-permission:")
  );
}

function markLocalLiuAgentBubbleOnlyOperation(operation, context = {}) {
  if (!operation || typeof operation !== "object") return operation;
  const meta =
    operation.meta && typeof operation.meta === "object" ? operation.meta : {};
  return {
    ...operation,
    meta: {
      ...meta,
      local_liuagent_operation: "true",
      source: "tauri_liuagent_local_chat",
      chat_session_id:
        String(meta.chat_session_id || "").trim() ||
        String(context.chatSessionId || "").trim(),
      cwd:
        String(meta.cwd || "").trim() ||
        String(context.workspacePath || "").trim(),
    },
  };
}

function localLiuAgentRuntimeEventsFromResult(result = {}) {
  if (Array.isArray(result?.runtimeEvents)) return result.runtimeEvents;
  if (Array.isArray(result?.runtime_events)) return result.runtime_events;
  return [];
}

function localLiuAgentConversationLifecycleFromResult(result = {}) {
  const lifecycle =
    result?.conversationLifecycle && typeof result.conversationLifecycle === "object"
      ? result.conversationLifecycle
      : result?.conversation_lifecycle && typeof result.conversation_lifecycle === "object"
        ? result.conversation_lifecycle
        : null;
  if (!lifecycle || !Array.isArray(lifecycle.nodes)) return null;
  return lifecycle;
}

function localLiuAgentLifecycleNodeStatus(node = {}) {
  const normalized = String(node?.status || "").trim();
  if (normalized === "ended") return "success";
  if (normalized === "completed") return "success";
  if (normalized === "failed") return "error";
  if (normalized === "waiting") return "warning";
  return "info";
}

function localLiuAgentLifecycleNodeKind(node = {}) {
  const type = String(node?.type || "").trim();
  if (type === "understand_requirement") return "model_call";
  if (type === "execute_task") {
    return normalizeMessageProcessEntryKind(node?.kind || "tool_result");
  }
  if (type === "final_solution") return "model_call";
  return "progress_update";
}

function localLiuAgentLifecycleNodeTitle(node = {}) {
  const type = String(node?.type || "").trim();
  const title = String(node?.title || "").trim();
  if (type === "start") return title || "开始";
  if (type === "understand_requirement") return title || "理解需求";
  if (type === "execute_task") return title || "执行任务";
  if (type === "final_solution") return title || "最终方案";
  return title || "生命周期节点";
}

function localLiuAgentLifecycleNodeProcessEntry(node = {}, lifecycle = {}) {
  const id = String(node?.id || "").trim() || `lifecycle-${Date.now()}`;
  const summary = String(node?.summary || "").trim();
  const title = localLiuAgentLifecycleNodeTitle(node);
  const toolCallId = String(node?.tool_call_id || node?.toolCallId || "").trim();
  return {
    id,
    text: [title, summary ? `  - ${summary}` : ""].filter(Boolean).join("\n"),
    level: localLiuAgentLifecycleNodeStatus(node),
    kind: localLiuAgentLifecycleNodeKind(node),
    eventType: "conversation_lifecycle",
    toolCallId,
    payload: {
      ...node,
      event_type: "conversation_lifecycle",
      lifecycle_version: lifecycle?.version || "desktop-conversation-lifecycle/v1",
      runtime_session_id: lifecycle?.session_id || lifecycle?.sessionId || "",
      chat_session_id: lifecycle?.chat_session_id || lifecycle?.chatSessionId || "",
      conversation_context:
        lifecycle?.conversation_context || lifecycle?.conversationContext || {},
      content: node?.content || {},
      arguments: node?.arguments || {},
    },
    autoExpand: false,
  };
}

function applyLocalLiuAgentConversationLifecycle(row, result = {}) {
  const lifecycle = localLiuAgentConversationLifecycleFromResult(result);
  if (!row || !lifecycle) return false;
  const lifecycleEntries = lifecycle.nodes.map((node) =>
    localLiuAgentLifecycleNodeProcessEntry(node, lifecycle),
  );
  const existing = Array.isArray(row.processLog) ? row.processLog.slice() : [];
  const hasRuntimeEntries = existing.some((item) => {
    const eventType = String(item?.eventType || item?.event_type || "").trim();
    return eventType && eventType !== "conversation_lifecycle";
  });
  if (hasRuntimeEntries) return false;
  if (result?.ok === false) {
    const existingIds = new Set(existing.map((item) => String(item?.id || "").trim()));
    row.processLog = existing.concat(
      lifecycleEntries.filter((item) => !existingIds.has(String(item?.id || "").trim())),
    );
  } else {
    row.processLog = lifecycleEntries;
  }
  row.processExpanded = true;
  return true;
}

function localLiuAgentRuntimeEventPayload(event = {}) {
  return event?.payload && typeof event.payload === "object" ? event.payload : {};
}

function localLiuAgentRuntimeEventPhase(event = {}) {
  const type = String(event?.type || "").trim();
  const payload = localLiuAgentRuntimeEventPayload(event);
  if (type === "approval_required") return "waiting_user";
  if (
    type === "model_call_started" ||
    type === "tool_call_started" ||
    type === "command_started" ||
    type === "command_output_chunk"
  )
    return "running";
  if (type === "model_step") return payload?.ok === false ? "failed" : "completed";
  if (type === "tool_result") return payload?.ok === false ? "failed" : "completed";
  if (type === "command_finished") return payload?.ok === false ? "failed" : "completed";
  if (type === "state_changed") {
    const to = String(payload?.to || "").trim();
    if (to === "waiting_approval" || to === "waiting_user") return "waiting_user";
    if (to === "failed") return "failed";
    if (to === "completed") return "completed";
    if (to === "cancelled") return "blocked";
  }
  return "running";
}

function compactLocalLiuAgentInline(value, limit = 180) {
  const normalized = String(value || "").replace(/\s+/g, " ").trim();
  if (!normalized || normalized.length <= limit) return normalized;
  return `${normalized.slice(0, limit)}...`;
}

function localLiuAgentToolTraceVerb(toolName = "") {
  const normalized = String(toolName || "").trim();
  if (normalized === "list_files") return "查看目录";
  if (normalized === "search_text") return "搜索文本";
  if (normalized === "read_file") return "读取文件";
  if (normalized === "run_command") return "执行命令";
  if (normalized === "check_command_risk") return "检查命令风险";
  if (normalized === "write_file") return "写入文件";
  if (normalized === "apply_patch") return "应用补丁";
  if (normalized === "delete_file") return "删除文件";
  if (["http_get", "http_post", "download_file"].includes(normalized)) return "访问网络";
  if (["list_mcp_tools", "read_mcp_resource", "call_mcp_tool"].includes(normalized)) return "调用 MCP";
  return normalized || "Tool";
}

function localLiuAgentToolTraceArgument(payload = {}) {
  const toolName = String(payload?.tool_name || payload?.toolName || "").trim();
  const args =
    payload?.arguments && typeof payload.arguments === "object" && !Array.isArray(payload.arguments)
      ? payload.arguments
      : {};
  if (toolName === "run_command" || toolName === "check_command_risk") {
    return String(args.cmd || args.command || payload?.cmd || payload?.command || "").trim();
  }
  if (toolName === "read_file" || toolName === "write_file" || toolName === "delete_file") {
    return String(args.path || args.file || "").trim();
  }
  if (toolName === "apply_patch") {
    return String(args.path || args.file || args.target || "patch").trim();
  }
  if (toolName === "search_text") {
    return String(args.query || args.pattern || args.text || "").trim();
  }
  if (toolName === "list_files") {
    return String(args.path || args.directory || ".").trim();
  }
  if (toolName === "http_get" || toolName === "http_post" || toolName === "download_file") {
    return String(args.url || "").trim();
  }
  if (toolName === "call_mcp_tool") {
    return [args.server, args.tool_name || args.name].filter(Boolean).join(".");
  }
  return String(payload?.arguments_preview || payload?.argumentsPreview || "").trim();
}

function localLiuAgentToolTraceSubject(payload = {}) {
  const argument = compactLocalLiuAgentInline(localLiuAgentToolTraceArgument(payload), 220);
  const toolName = String(payload?.tool_name || payload?.toolName || "").trim();
  const verb = localLiuAgentToolTraceVerb(toolName);
  return `${verb}${argument ? `(${argument})` : ""}`;
}

function localLiuAgentToolResultLabel(toolName = "") {
  const normalized = String(toolName || "").trim();
  if (normalized === "list_files") return "List files";
  if (normalized === "search_text") return "Search text";
  if (normalized === "read_file") return "Read file";
  if (normalized === "run_command") return "执行命令";
  if (normalized === "check_command_risk") return "检查命令风险";
  if (normalized === "write_file") return "Write file";
  if (normalized === "apply_patch") return "Apply patch";
  if (normalized === "delete_file") return "Delete file";
  if (normalized === "http_get") return "HTTP GET";
  if (normalized === "http_post") return "HTTP POST";
  if (normalized === "download_file") return "下载文件";
  if (normalized === "call_mcp_tool") return "调用 MCP 工具";
  if (normalized === "list_mcp_tools") return "列出 MCP 工具";
  if (normalized === "read_mcp_resource") return "读取 MCP 资源";
  return normalized || "Tool";
}

function localLiuAgentRuntimeEventTranscriptText(event = {}) {
  const type = String(event?.type || "").trim();
  const payload = localLiuAgentRuntimeEventPayload(event);
  if (type === "progress_update") {
    const summary = compactLocalLiuAgentInline(payload?.summary || "", 360);
    const currentFocus = compactLocalLiuAgentInline(
      payload?.current_focus || payload?.currentFocus || "",
      260,
    );
    const nextAction = compactLocalLiuAgentInline(
      payload?.next_action || payload?.nextAction || "",
      260,
    );
    return [
      currentFocus || summary,
      currentFocus && summary && summary !== currentFocus ? `  - ${summary}` : "",
      nextAction ? `  - 完成后：${nextAction}` : "",
    ]
      .filter(Boolean)
      .join("\n");
  }
  if (type === "model_call_started") return "";
  if (type === "model_step") {
    const error = compactLocalLiuAgentInline(payload?.error || payload?.error_code || "", 260);
    if (payload?.ok !== false) return "";
    return ["模型调用失败", error ? `  - 错误：${error}` : ""]
      .filter(Boolean)
      .join("\n");
  }
  if (type === "command_started") {
    const cmd = compactLocalLiuAgentInline(payload?.cmd || payload?.command || "", 260);
    const cwd = String(payload?.cwd || "").trim();
    return [
      cmd ? `正在执行命令：${cmd}` : "正在执行命令",
      cwd ? `  - cwd=${cwd}` : "",
    ]
      .filter(Boolean)
      .join("\n");
  }
  if (type === "command_output_chunk") {
    const stream = String(payload?.stream || "stdout").trim();
    const text = compactLocalLiuAgentInline(payload?.text || "", 500);
    return [`Output (${stream})`, text ? `  ${text}` : ""].filter(Boolean).join("\n");
  }
  if (type === "command_finished") {
    const exitCode = payload?.exit_code ?? payload?.exitCode;
    const durationMs = payload?.duration_ms ?? payload?.durationMs;
    const summary = compactLocalLiuAgentInline(payload?.summary || payload?.error || "", 260);
    return [
      "命令执行完成",
      exitCode !== undefined && exitCode !== null ? `  - exit_code=${exitCode}` : "",
      durationMs !== undefined && durationMs !== null ? `  - duration=${durationMs}ms` : "",
      summary ? `  - ${summary}` : "",
    ]
      .filter(Boolean)
      .join("\n");
  }
  if (type === "tool_call_started") {
    const toolName = String(payload?.tool_name || payload?.toolName || "").trim();
    const subject = localLiuAgentToolTraceSubject(payload);
    const index = Number(payload?.tool_index || payload?.toolIndex || 0) || 0;
    const count = Number(payload?.tool_count || payload?.toolCount || 0) || 0;
    const progress = index > 0 && count > 0 ? ` ${index}/${count}` : "";
    const summary = compactLocalLiuAgentInline(payload?.summary || "", 260);
    const argumentsPreview = compactLocalLiuAgentInline(
      payload?.arguments_preview || payload?.argumentsPreview || "",
      1200,
    );
    return [
      subject ? `正在${subject}${progress}` : `正在调用工具${progress}`,
      summary ? `  - ${summary}` : "",
      argumentsPreview ? `  - 参数：${argumentsPreview}` : "",
    ]
      .filter(Boolean)
      .join("\n");
  }
  if (type === "tool_result") {
    const toolName = String(payload?.tool_name || payload?.toolName || "").trim();
    const resultLabel = localLiuAgentToolResultLabel(toolName);
    const summary = compactLocalLiuAgentInline(
      payload?.summary || payload?.error_code || payload?.error || "",
      260,
    );
    const argumentsPreview = compactLocalLiuAgentInline(
      payload?.arguments_preview || payload?.argumentsPreview || "",
      1200,
    );
    return [
      `完成：${resultLabel}`,
      summary ? `  - ${summary}` : "",
      argumentsPreview ? `  - 参数：${argumentsPreview}` : "",
    ]
      .filter(Boolean)
      .join("\n");
  }
  if (type === "approval_required") {
    const action = String(payload?.action || "").trim();
    const risk = String(payload?.risk || "").trim();
    const toolName = String(payload?.tool_name || payload?.toolName || "").trim();
    const preview =
      payload?.preview && typeof payload.preview === "object" ? payload.preview : {};
    const cmd = compactLocalLiuAgentInline(preview.cmd || preview.command || "", 260);
    return [
      "等待授权",
      toolName ? `  - 工具：${toolName}` : "",
      cmd ? `  - 命令：${cmd}` : "",
      action ? `  - 动作：${action}` : "",
      risk ? `  - 风险：${risk}` : "",
    ]
      .filter(Boolean)
      .join("\n");
  }
  return "";
}

function localLiuAgentRuntimeEventSummary(event = {}) {
  const type = String(event?.type || "").trim();
  const payload = localLiuAgentRuntimeEventPayload(event);
  if (type === "progress_update") {
    const summary = String(payload?.summary || "").trim();
    const currentFocus = String(payload?.current_focus || payload?.currentFocus || "").trim();
    const nextAction = String(payload?.next_action || payload?.nextAction || "").trim();
    return [currentFocus || summary, nextAction ? `下一步：${nextAction}` : ""]
      .filter(Boolean)
      .join(" · ");
  }
  if (type === "approval_required") {
    const action = String(payload?.action || "").trim();
    const risk = String(payload?.risk || "").trim();
    return [action ? `等待授权：${action}` : "等待本机工具授权", risk]
      .filter(Boolean)
      .join(" · ");
  }
  if (type === "state_changed") {
    const to = String(payload?.to || "").trim();
    if (to === "waiting_approval") return "本地会话等待授权";
    if (to === "completed") return "本地会话完成";
    if (to === "failed") return "本地会话失败";
    return to ? `本地会话状态：${to}` : "本地会话状态已更新";
  }
  if (type === "model_step") {
    const index = Number(payload?.index || 0) || 0;
    const summary = String(payload?.summary || "").trim();
    const error = String(payload?.error || "").trim();
    const errorCode = String(payload?.error_code || payload?.errorCode || "").trim();
    const provider = String(payload?.provider_id || payload?.providerId || "").trim();
    const model = String(payload?.model_name || payload?.modelName || "").trim();
    const toolCount = Number(payload?.tool_call_count || payload?.toolCallCount || 0) || 0;
    const title = index > 0 ? `模型步骤 ${index}` : "模型步骤";
    const runtime = [provider, model].filter(Boolean).join(" / ");
    if (payload?.ok === false) {
      const failure = compactLocalLiuAgentInline(
        [errorCode, error || summary].filter(Boolean).join(" "),
        220,
      );
      return [title, runtime, failure ? `调用失败：${failure}` : "调用失败"]
        .filter(Boolean)
        .join(" · ");
    }
    const toolText = toolCount > 0 ? `返回 ${toolCount} 个工具调用` : "未继续调用工具";
    return [title, runtime, summary || toolText].filter(Boolean).join(" · ");
  }
  if (type === "model_call_started") {
    const index = Number(payload?.index || 0) || 0;
    const provider = String(payload?.provider_id || payload?.providerId || "").trim();
    const model = String(payload?.model_name || payload?.modelName || "").trim();
    const messageCount = Number(payload?.message_count || payload?.messageCount || 0) || 0;
    const title = index > 0 ? `模型步骤 ${index}` : "模型步骤";
    const runtime = [provider, model].filter(Boolean).join(" / ");
    const contextText = messageCount > 0 ? `上下文 ${messageCount} 条` : "";
    return [title, runtime, contextText, "请求中"].filter(Boolean).join(" · ");
  }
  if (type === "command_started") {
    const cmd = String(payload?.cmd || payload?.command || "").trim();
    return cmd ? `执行命令：${cmd}` : "执行命令";
  }
  if (type === "command_output_chunk") {
    const stream = String(payload?.stream || "stdout").trim();
    const text = compactLocalLiuAgentInline(payload?.text || "", 120);
    return text ? `Output (${stream}): ${text}` : `Output (${stream})`;
  }
  if (type === "command_finished") {
    const exitCode = payload?.exit_code ?? payload?.exitCode;
    const summary = String(payload?.summary || payload?.error || "").trim();
    return [exitCode !== undefined && exitCode !== null ? `命令退出码 ${exitCode}` : "命令完成", summary]
      .filter(Boolean)
      .join(" · ");
  }
  if (type === "tool_call_started") {
    const toolName = String(payload?.tool_name || payload?.toolName || "").trim();
    const summary = String(payload?.summary || "").trim();
    const toolIndex = Number(payload?.tool_index || payload?.toolIndex || 0) || 0;
    const toolCount = Number(payload?.tool_count || payload?.toolCount || 0) || 0;
    const subject = localLiuAgentToolTraceSubject(payload);
    const toolLabel =
      subject && toolIndex > 0 && toolCount > 0
        ? `${subject} ${toolIndex}/${toolCount}`
        : subject || toolName || "本地工具";
    const argumentsPreview = String(
      payload?.arguments_preview || payload?.argumentsPreview || "",
    ).trim();
    return [toolLabel, summary || argumentsPreview || "运行中"]
      .filter(Boolean)
      .join(" · ");
  }
  if (type === "tool_result") {
    const toolName = String(payload?.tool_name || payload?.toolName || "").trim();
    const summary = String(payload?.summary || "").trim();
    return [`完成：${localLiuAgentToolResultLabel(toolName)}`, summary]
      .filter(Boolean)
      .join(" · ");
  }
  return type ? `本地事件：${type}` : "本地运行时事件";
}

function localLiuAgentRuntimeEventOperation(event = {}, context = {}) {
  const type = String(event?.type || "").trim();
  if (!type || type === "message") return null;
  const payload = localLiuAgentRuntimeEventPayload(event);
  if (
    type === "tool_result" &&
    String(payload?.error_code || payload?.errorCode || "").trim() === "permission.required"
  ) {
    return null;
  }
  const eventId = String(event?.event_id || event?.eventId || "").trim();
  const runtimeSessionId = String(
    event?.runtime_session_id || event?.runtimeSessionId || event?.session_id || "",
  ).trim();
  const phase = localLiuAgentRuntimeEventPhase(event);
  const summary = localLiuAgentRuntimeEventSummary(event);
  const toolName = String(payload?.tool_name || payload?.toolName || "").trim();
  const modelStepIndex = Number(payload?.index || 0) || 0;
  const requestId = String(payload?.requestId || payload?.request_id || "").trim();
  const argumentsPreview = String(
    payload?.arguments_preview || payload?.argumentsPreview || "",
  ).trim();
  const operationId =
    type === "approval_required" && requestId
      ? localLiuAgentPermissionOperationId(requestId, eventId)
      : eventId ||
        `local-agent-event:${runtimeSessionId || context.assistantMessageId || "unknown"}:${type}`;
  return {
    operationId,
    kind:
      type === "approval_required"
        ? "approval"
        : type === "model_step" || type === "model_call_started" || type === "progress_update"
          ? "model"
        : type === "command_started" || type === "command_output_chunk" || type === "command_finished"
          ? "tool"
        : type === "tool_result" || type === "tool_call_started"
          ? "tool"
          : "request",
    title:
      type === "approval_required"
        ? "桌面本地工具授权"
        : type === "command_started"
          ? "执行命令"
        : type === "command_output_chunk"
          ? "Command output"
        : type === "command_finished"
          ? "Command finished"
        : type === "progress_update"
          ? "推进当前任务"
        : type === "model_step"
          ? `本地模型步骤 ${modelStepIndex || ""}`.trim()
        : type === "model_call_started"
          ? `本地模型步骤 ${modelStepIndex || ""} 请求中`.trim()
        : type === "tool_result"
          ? `完成：${localLiuAgentToolResultLabel(toolName)}`
        : type === "tool_call_started"
          ? localLiuAgentToolTraceSubject(payload)
          : "桌面本地 Agent Runtime",
    summary,
    detail:
      type === "approval_required"
        ? nativeLiuAgentPermissionText(payload, { toolName: toolName || "本地工具" })
        : type === "tool_call_started"
          ? argumentsPreview
        : String(payload?.error_code || payload?.error || "").trim(),
    phase,
    actionType: type === "approval_required" ? "approve" : "none",
    meta: {
      local_liuagent_operation: "true",
      agent_runtime_event: "true",
      source: "tauri_liuagent_local_chat",
      event_type: type,
      runtime_session_id: runtimeSessionId,
      chat_session_id:
        String(event?.chat_session_id || event?.chatSessionId || "").trim() ||
        String(context.chatSessionId || "").trim(),
      request_id: requestId,
      model_step_index: modelStepIndex,
      provider_id: String(payload?.provider_id || payload?.providerId || "").trim(),
      model_name: String(payload?.model_name || payload?.modelName || "").trim(),
      tool_call_count: Number(payload?.tool_call_count || payload?.toolCallCount || 0) || 0,
      tool_name: toolName,
      tool_index: Number(payload?.tool_index || payload?.toolIndex || 0) || 0,
      tool_count: Number(payload?.tool_count || payload?.toolCount || 0) || 0,
      arguments_preview: argumentsPreview,
      tool_call_id: String(payload?.tool_call_id || payload?.toolCallId || "").trim(),
      tool_result_id: String(
        payload?.tool_result_id || payload?.toolResultId || "",
      ).trim(),
      cwd: String(context.workspacePath || "").trim(),
    },
  };
}

function localLiuAgentRuntimeEventProcessKind(event = {}) {
  const type = String(event?.type || "").trim();
  const payload = localLiuAgentRuntimeEventPayload(event);
  const toolName = String(payload?.tool_name || payload?.toolName || "").trim();
  if (type === "progress_update") return "progress_update";
  if (type === "model_call_started" || type === "model_step") return "model_call";
  if (type === "approval_required") return "permission";
  if (type === "command_output_chunk") return "command_output";
  if (type === "command_started" || type === "command_finished") return "command";
  if (toolName === "read_file") return "file_read";
  if (["list_files", "search_text"].includes(toolName)) return "file_search";
  if (["write_file", "apply_patch", "delete_file"].includes(toolName)) return "file_edit";
  if (["call_mcp_tool", "list_mcp_tools", "read_mcp_resource"].includes(toolName)) {
    return "mcp_call";
  }
  if (type === "tool_call_started") return "tool_call";
  if (type === "tool_result") return "tool_result";
  return "log";
}

function localLiuAgentRuntimeEventProcessLogEntry(event = {}, operation = null) {
  const type = String(event?.type || "").trim();
  const payload = localLiuAgentRuntimeEventPayload(event);
  const eventId = String(event?.event_id || event?.eventId || "").trim();
  const transcriptText = localLiuAgentRuntimeEventTranscriptText(event);
  const phase = operation
    ? operation.phase
    : localLiuAgentRuntimeEventPhase(event);
  return {
    id:
      eventId ||
      `local-agent-event:${String(event?.runtime_session_id || event?.runtimeSessionId || "").trim()}:${type}:${Date.now()}`,
    text: transcriptText || operation?.summary || localLiuAgentRuntimeEventSummary(event),
    level:
      phase === "failed"
        ? "error"
        : phase === "waiting_user"
          ? "warning"
          : phase === "completed"
            ? "success"
            : "info",
    kind: localLiuAgentRuntimeEventProcessKind(event),
    eventType: type,
    payload: {
      ...payload,
      event_type: type,
      runtime_session_id: String(
        event?.runtime_session_id || event?.runtimeSessionId || event?.session_id || "",
      ).trim(),
    },
    toolCallId: String(payload?.tool_call_id || payload?.toolCallId || "").trim(),
  };
}

function applyLocalLiuAgentReasoningContent(row, event = {}) {
  if (!row || String(event?.type || "").trim() !== "model_step") return false;
  const payload = localLiuAgentRuntimeEventPayload(event);
  const reasoningContent = String(
    payload?.reasoning_content || payload?.reasoningContent || "",
  ).trim();
  if (!reasoningContent) return false;
  row.reasoningContent = reasoningContent;
  return true;
}

function modelStepFailureMessageFromEvent(event = {}) {
  const payload = localLiuAgentRuntimeEventPayload(event);
  const index = Number(payload?.index || 0) || 0;
  const provider = String(payload?.provider_id || payload?.providerId || "").trim();
  const model = String(payload?.model_name || payload?.modelName || "").trim();
  const errorCode = String(payload?.error_code || payload?.errorCode || "").trim();
  const error = String(payload?.error || "").trim();
  const summary = String(payload?.summary || "").trim();
  const detail = compactLocalLiuAgentInline(
    stripLocalLiuAgentRequestDiagnostic(error || summary),
    260,
  );
  const lines = [
    `模型调用失败${index > 0 ? `（模型步骤 ${index}）` : ""}。`,
    [provider, model].filter(Boolean).length
      ? `模型：${[provider, model].filter(Boolean).join(" / ")}`
      : "",
    errorCode ? `错误码：${errorCode}` : "",
    detail ? `原因：${detail}` : "",
    "完整诊断见运行详情。",
  ].filter(Boolean);
  return lines.join("\n");
}

function stripLocalLiuAgentRequestDiagnostic(value = "") {
  let text = String(value || "").trim();
  for (const marker of [" request={", " request=[", "\nrequest={", "\nrequest=["]) {
    const index = text.indexOf(marker);
    if (index >= 0) {
      text = text.slice(0, index).trim();
    }
  }
  return text;
}

function applyLocalLiuAgentModelStepFailure(row, event = {}, context = {}) {
  if (!row || String(event?.type || "").trim() !== "model_step") return false;
  const payload = localLiuAgentRuntimeEventPayload(event);
  if (payload?.ok !== false) return false;
  const message = modelStepFailureMessageFromEvent(event);
  row.content = String(row.content || "").trim() || message;
  row.time = nowText();
  upsertMessageOperation(row, {
    operationId: `local-agent-running:${row.id}`,
    kind: "request",
    title: "桌面本地 Agent Runtime",
    summary: "本地模型调用失败",
    detail: String(payload?.error || payload?.summary || "").trim(),
    phase: "failed",
    actionType: "none",
    meta: {
      local_liuagent_operation: "true",
      agent_runtime_event: "true",
      source: "tauri_liuagent_local_chat",
      chat_session_id: String(context?.chatSessionId || "").trim(),
      cwd: String(context?.workspacePath || "").trim(),
      error_code: String(payload?.error_code || payload?.errorCode || "").trim(),
    },
  });
  upsertMessageOperation(row, {
    operationId: `local-agent:${row.id}`,
    kind: "request",
    title: "桌面本地 Agent Runtime",
    summary: "本地模型调用失败",
    detail: String(payload?.error || payload?.summary || "").trim(),
    phase: "failed",
    actionType: "none",
    meta: {
      local_liuagent_operation: "true",
      source: "tauri_liuagent_local_chat",
      chat_session_id: String(context?.chatSessionId || "").trim(),
      cwd: String(context?.workspacePath || "").trim(),
      error_code: String(payload?.error_code || payload?.errorCode || "").trim(),
    },
  });
  row.processExpanded = true;
  return true;
}

function shouldUpsertLocalLiuAgentRuntimeOperation(event = {}, operation = null) {
  if (!operation) return false;
  const type = String(event?.type || "").trim();
  if (type === "approval_required") return false;
  return shouldShowMessageOperationCard(operation);
}

function normalizeLocalLiuAgentRuntimeEpochMs(value) {
  const timestamp = Number(value || 0);
  return Number.isFinite(timestamp) && timestamp > 0 ? Math.round(timestamp) : 0;
}

function localLiuAgentRuntimeEventIsTerminal(event = {}) {
  const type = String(event?.type || "").trim();
  const payload = localLiuAgentRuntimeEventPayload(event);
  if (type === "model_step" && payload?.ok === false) return true;
  if (type !== "state_changed") return false;
  const to = String(payload?.to || "").trim();
  return ["completed", "failed", "cancelled"].includes(to);
}

function normalizeLocalLiuAgentRuntimeTiming({
  startedAt = 0,
  endedAt = 0,
  latestAt = 0,
  running = false,
} = {}) {
  const start = normalizeLocalLiuAgentRuntimeEpochMs(startedAt);
  const end = normalizeLocalLiuAgentRuntimeEpochMs(endedAt);
  const latest = normalizeLocalLiuAgentRuntimeEpochMs(latestAt);
  const effectiveEnd = end || (!running ? latest : 0);
  const duration =
    start && effectiveEnd && effectiveEnd >= start ? effectiveEnd - start : 0;
  return {
    startedAtEpochMs: start,
    endedAtEpochMs: effectiveEnd,
    latestEventAtEpochMs: latest,
    durationMs: duration,
  };
}

function applyLocalLiuAgentRuntimeTiming(row, timing = {}) {
  if (!row) return null;
  const current = normalizeLocalLiuAgentRuntimeTiming({
    startedAt: row.agentRuntimeStartedAtEpochMs,
    endedAt: row.agentRuntimeEndedAtEpochMs,
    latestAt: row.agentRuntimeLatestEventAtEpochMs,
    running: !row.agentRuntimeEndedAtEpochMs,
  });
  const incoming = normalizeLocalLiuAgentRuntimeTiming({
    startedAt: timing.startedAt,
    endedAt: timing.endedAt,
    latestAt: timing.latestAt,
    running: timing.running,
  });
  const startedAt =
    current.startedAtEpochMs && incoming.startedAtEpochMs
      ? Math.min(current.startedAtEpochMs, incoming.startedAtEpochMs)
      : current.startedAtEpochMs || incoming.startedAtEpochMs;
  const latestAt = Math.max(
    current.latestEventAtEpochMs,
    incoming.latestEventAtEpochMs,
    incoming.endedAtEpochMs,
  );
  const endedAt =
    current.endedAtEpochMs && incoming.endedAtEpochMs
      ? Math.max(current.endedAtEpochMs, incoming.endedAtEpochMs)
      : current.endedAtEpochMs || incoming.endedAtEpochMs;
  const normalized = normalizeLocalLiuAgentRuntimeTiming({
    startedAt,
    endedAt,
    latestAt,
    running: !endedAt,
  });
  if (normalized.startedAtEpochMs) {
    row.agentRuntimeStartedAtEpochMs = normalized.startedAtEpochMs;
  }
  if (normalized.latestEventAtEpochMs) {
    row.agentRuntimeLatestEventAtEpochMs = normalized.latestEventAtEpochMs;
  }
  if (normalized.endedAtEpochMs) {
    row.agentRuntimeEndedAtEpochMs = normalized.endedAtEpochMs;
  }
  row.agentRuntimeDurationMs = normalized.durationMs;
  row.agentRuntimeDurationLabel = normalized.durationMs
    ? formatDurationMs(normalized.durationMs)
    : "";
  applyMessageExecutionTiming(row, {
    startedAt: normalized.startedAtEpochMs,
    endedAt: normalized.endedAtEpochMs,
  });
  return normalized;
}

function updateLocalLiuAgentRuntimeTimingFromEvent(row, event = {}, options = {}) {
  const eventAt = localLiuAgentRuntimeEventCreatedAt(event);
  return applyLocalLiuAgentRuntimeTiming(row, {
    startedAt: options.startedAt || eventAt,
    latestAt: eventAt,
    endedAt:
      options.endedAt ||
      (localLiuAgentRuntimeEventIsTerminal(event) ? eventAt : 0),
    running: !localLiuAgentRuntimeEventIsTerminal(event),
  });
}

function updateLocalLiuAgentRuntimeTimingFromResult(row, result = {}, options = {}) {
  const events = localLiuAgentRuntimeEventsFromResult(result);
  let firstEventAt = 0;
  let latestEventAt = 0;
  let terminalEventAt = 0;
  for (const event of events) {
    const eventAt = localLiuAgentRuntimeEventCreatedAt(event);
    if (!eventAt) continue;
    firstEventAt = firstEventAt ? Math.min(firstEventAt, eventAt) : eventAt;
    latestEventAt = Math.max(latestEventAt, eventAt);
    if (localLiuAgentRuntimeEventIsTerminal(event)) {
      terminalEventAt = Math.max(terminalEventAt, eventAt);
    }
  }
  const waitingPermission = Boolean(localLiuAgentPermissionRequestFromChatResult(result));
  const hasFinalResult = result?.ok !== undefined && result?.ok !== null;
  const endedAt =
    normalizeLocalLiuAgentRuntimeEpochMs(options.endedAt) ||
    terminalEventAt ||
    (!waitingPermission && hasFinalResult ? latestEventAt || Date.now() : 0);
  return applyLocalLiuAgentRuntimeTiming(row, {
    startedAt: options.startedAt || firstEventAt,
    latestAt: latestEventAt || endedAt,
    endedAt,
    running: waitingPermission || !endedAt,
  });
}

function messageAgentRuntimeDurationLabel(row = {}) {
  const durationMs =
    Number(row?.messageExecutionDurationMs || row?.agentRuntimeDurationMs || 0) || 0;
  if (durationMs > 0) return `耗时 ${formatDurationMs(durationMs)}`;
  const startedAt = normalizeLocalLiuAgentRuntimeEpochMs(
    row?.messageExecutionStartedAtEpochMs || row?.agentRuntimeStartedAtEpochMs,
  );
  if (
    !startedAt ||
    row?.messageExecutionEndedAtEpochMs ||
    row?.agentRuntimeEndedAtEpochMs
  ) {
    return "";
  }
  const elapsedMs = Date.now() - startedAt;
  return elapsedMs > 0 ? `已运行 ${formatDurationMs(elapsedMs)}` : "";
}

function localLiuAgentRuntimeTimingSourceContext(row = {}) {
  const startedAt = normalizeLocalLiuAgentRuntimeEpochMs(
    row?.agentRuntimeStartedAtEpochMs,
  );
  const endedAt = normalizeLocalLiuAgentRuntimeEpochMs(
    row?.agentRuntimeEndedAtEpochMs,
  );
  const durationMs = Number(row?.agentRuntimeDurationMs || 0) || 0;
  return {
    runtime_started_at_epoch_ms: startedAt || null,
    runtime_ended_at_epoch_ms: endedAt || null,
    runtime_duration_ms: durationMs || null,
    runtime_duration_label: durationMs ? formatDurationMs(durationMs) : "",
  };
}

function applyMessageExecutionTiming(row, timing = {}) {
  if (!row) return null;
  const currentStartedAt = normalizeLocalLiuAgentRuntimeEpochMs(
    row.messageExecutionStartedAtEpochMs || row.agentRuntimeStartedAtEpochMs,
  );
  const currentEndedAt = normalizeLocalLiuAgentRuntimeEpochMs(
    row.messageExecutionEndedAtEpochMs || row.agentRuntimeEndedAtEpochMs,
  );
  const incomingStartedAt = normalizeLocalLiuAgentRuntimeEpochMs(timing.startedAt);
  const incomingEndedAt = normalizeLocalLiuAgentRuntimeEpochMs(timing.endedAt);
  const startedAt =
    currentStartedAt && incomingStartedAt
      ? Math.min(currentStartedAt, incomingStartedAt)
      : currentStartedAt || incomingStartedAt;
  const endedAt =
    currentEndedAt && incomingEndedAt
      ? Math.max(currentEndedAt, incomingEndedAt)
      : currentEndedAt || incomingEndedAt;
  const durationMs =
    startedAt && endedAt && endedAt >= startedAt ? endedAt - startedAt : 0;
  if (startedAt) {
    row.messageExecutionStartedAtEpochMs = startedAt;
  }
  if (endedAt) {
    row.messageExecutionEndedAtEpochMs = endedAt;
  }
  row.messageExecutionDurationMs = durationMs;
  row.messageExecutionDurationLabel = durationMs ? formatDurationMs(durationMs) : "";
  return {
    startedAtEpochMs: startedAt,
    endedAtEpochMs: endedAt,
    durationMs,
  };
}

function finishMessageExecutionTiming(row, endedAt = Date.now()) {
  return applyMessageExecutionTiming(row, {
    endedAt,
  });
}

function applyLocalLiuAgentRuntimeEvents(row, result = {}, context = {}) {
  if (!row) return;
  const startedAt = normalizeLocalLiuAgentRuntimeEpochMs(context?.startedAt);
  for (const event of localLiuAgentRuntimeEventsFromResult(result)) {
    if (!markLocalLiuAgentRuntimeEventSeen(event)) continue;
    const eventType = String(event?.type || "").trim();
    const payload = localLiuAgentRuntimeEventPayload(event);
    if (
      String(event?.type || "").trim() === "tool_result" &&
      String(payload?.error_code || payload?.errorCode || "").trim() ===
        "permission.required"
    ) {
      continue;
    }
    updateLocalLiuAgentRuntimeTimingFromEvent(row, event, { startedAt });
    if (["plan_created", "plan_updated", "plan_completed"].includes(eventType)) {
      applyLiuAgentPlanEvent(
        row,
        {
          run_id: String(
            event?.runtime_session_id || event?.runtimeSessionId || event?.run_id || "",
          ).trim(),
          event_type: eventType,
          event,
        },
        String(context?.requestId || context?.assistantMessageId || row.id || "").trim(),
      );
      continue;
    }
    applyLocalLiuAgentReasoningContent(row, event);
    applyLocalLiuAgentModelStepFailure(row, event, context);
    const operation = localLiuAgentRuntimeEventOperation(event, {
      ...context,
      assistantMessageId: row.id,
    });
    if (shouldUpsertLocalLiuAgentRuntimeOperation(event, operation)) {
      upsertMessageOperation(row, operation);
    }
    appendMessageProcessLog(row, {
      ...localLiuAgentRuntimeEventProcessLogEntry(event, operation),
    });
  }
  updateLocalLiuAgentRuntimeTimingFromResult(row, result, { startedAt });
  applyLocalLiuAgentConversationLifecycle(row, result);
}

function localLiuAgentResultModelRuntime(result = {}) {
  const modelResult =
    result?.modelResult && typeof result.modelResult === "object"
      ? result.modelResult
      : result?.model_result && typeof result.model_result === "object"
        ? result.model_result
        : {};
  return modelResult && typeof modelResult === "object" ? modelResult : {};
}

function localLiuAgentResultCurrentStateDelta(result = {}) {
  const modelRuntime = localLiuAgentResultModelRuntime(result);
  const currentStateDelta =
    modelRuntime?.currentStateDelta && typeof modelRuntime.currentStateDelta === "object"
      ? modelRuntime.currentStateDelta
      : modelRuntime?.current_state_delta &&
          typeof modelRuntime.current_state_delta === "object"
        ? modelRuntime.current_state_delta
        : result?.currentStateDelta && typeof result.currentStateDelta === "object"
          ? result.currentStateDelta
          : result?.current_state_delta && typeof result.current_state_delta === "object"
            ? result.current_state_delta
            : {};
  return currentStateDelta && typeof currentStateDelta === "object"
    ? currentStateDelta
    : {};
}

function localLiuAgentResultStructuredState(result = {}, key = "") {
  const currentStateDelta = localLiuAgentResultCurrentStateDelta(result);
  const camelKey = String(key || "").replace(/_([a-z])/g, (_, char) =>
    String(char || "").toUpperCase(),
  );
  const value =
    currentStateDelta?.[camelKey] && typeof currentStateDelta[camelKey] === "object"
      ? currentStateDelta[camelKey]
      : currentStateDelta?.[key] && typeof currentStateDelta[key] === "object"
        ? currentStateDelta[key]
        : {};
  return value && typeof value === "object" ? value : {};
}

function localLiuAgentVerificationSummary(verificationReport = {}) {
  const checks = Array.isArray(verificationReport?.checks)
    ? verificationReport.checks
    : [];
  const status = String(
    verificationReport?.overallStatus || verificationReport?.overall_status || "",
  ).trim();
  const checkSummary = checks
    .map((check) => {
      const type = String(check?.type || check?.checkType || check?.check_type || "").trim();
      const checkStatus = String(check?.status || "").trim();
      return [type, checkStatus].filter(Boolean).join(":");
    })
    .filter(Boolean)
    .join(", ");
  return [`Verification ${status || "-"}`, checkSummary].filter(Boolean).join(" · ");
}

function appendLocalLiuAgentStructuredStateOperations(row, result = {}, context = {}) {
  if (!row) return;
  const planState = localLiuAgentResultStructuredState(result, "plan_state");
  const verificationReport = localLiuAgentResultStructuredState(
    result,
    "verification_report",
  );
  const memoryWritePlan = localLiuAgentResultStructuredState(result, "memory_write_plan");
  const baseMeta = {
    local_liuagent_operation: "true",
    agent_runtime_event: "true",
    source: "tauri_liuagent_local_chat",
    chat_session_id: String(context?.chatSessionId || "").trim(),
    cwd: String(context?.workspacePath || "").trim(),
  };
  if (String(planState?.version || "").trim()) {
    const nodes = Array.isArray(planState?.nodes) ? planState.nodes : [];
    upsertMessageOperation(row, {
      operationId: `local-agent-plan:${row.id}`,
      kind: "request",
      title: "Plan state",
      summary: `Plan ${String(planState?.status || "-").trim()} · ${nodes.length} nodes`,
      detail: String(planState?.rootGoal || planState?.root_goal || "").trim(),
      phase:
        String(planState?.status || "").trim() === "completed"
          ? "completed"
          : "running",
      actionType: "none",
      meta: {
        ...baseMeta,
        structured_state: "plan_state",
        current_node_id: String(
          planState?.currentNodeId || planState?.current_node_id || "",
        ).trim(),
      },
    });
  }
  if (String(verificationReport?.version || "").trim()) {
    const overallStatus = String(
      verificationReport?.overallStatus || verificationReport?.overall_status || "",
    ).trim();
    upsertMessageOperation(row, {
      operationId: `local-agent-verification:${row.id}`,
      kind: "request",
      title: "Verification report",
      summary: localLiuAgentVerificationSummary(verificationReport),
      detail: (Array.isArray(verificationReport?.evidence)
        ? verificationReport.evidence
        : []
      )
        .filter(Boolean)
        .join("\n"),
      phase:
        overallStatus === "passed"
          ? "completed"
          : overallStatus === "blocked"
            ? "blocked"
            : "failed",
      actionType: "none",
      meta: {
        ...baseMeta,
        structured_state: "verification_report",
        overall_status: overallStatus,
      },
    });
    appendMessageProcessLog(row, {
      id: `local-agent-verification-log:${row.id}`,
      text: localLiuAgentVerificationSummary(verificationReport),
      level:
        overallStatus === "passed"
          ? "success"
          : overallStatus === "blocked"
            ? "warning"
            : "error",
      kind: "verification",
      payload: verificationReport,
    });
  }
  if (String(memoryWritePlan?.version || "").trim()) {
    const items = Array.isArray(memoryWritePlan?.items) ? memoryWritePlan.items : [];
    appendMessageProcessLog(row, {
      id: `local-agent-memory-log:${row.id}`,
      text: `Memory classifier · ${items.length} writes/candidates`,
      level: "info",
      kind: "memory",
      payload: memoryWritePlan,
    });
  }
}

function localLiuAgentActiveRunForChatSession(chatSessionId = "") {
  localLiuAgentActiveRunVersion.value;
  const normalizedChatSessionId = String(chatSessionId || "").trim();
  if (!normalizedChatSessionId) return null;
  return localLiuAgentActiveRuns.get(normalizedChatSessionId) || null;
}

function setLocalLiuAgentActiveRun(chatSessionId = "", run = null) {
  const normalizedChatSessionId = String(chatSessionId || "").trim();
  if (!normalizedChatSessionId || !run) return;
  localLiuAgentActiveRuns.set(normalizedChatSessionId, run);
  localLiuAgentActiveRunVersion.value += 1;
  startLocalLiuAgentRuntimeEventPolling();
}

function deleteLocalLiuAgentActiveRun(chatSessionId = "") {
  const normalizedChatSessionId = String(chatSessionId || "").trim();
  if (!normalizedChatSessionId) return false;
  const deleted = localLiuAgentActiveRuns.delete(normalizedChatSessionId);
  if (deleted) {
    localLiuAgentActiveRunVersion.value += 1;
    stopLocalLiuAgentRuntimeEventPollingIfIdle();
  }
  return deleted;
}

const currentChatSessionLocalLiuAgentRunning = computed(() =>
  Boolean(localLiuAgentActiveRunForChatSession(currentChatSessionId.value)),
);

function localLiuAgentActiveRunRow(run) {
  const assistantMessageId = String(run?.assistantMessageId || "").trim();
  if (!assistantMessageId) return null;
  return messages.value.find((row) => String(row?.id || "").trim() === assistantMessageId) || null;
}

function localLiuAgentRuntimeEventKey(event = {}) {
  const eventId = String(event?.event_id || event?.eventId || "").trim();
  if (eventId) return eventId;
  return [
    String(event?.runtime_session_id || event?.runtimeSessionId || "").trim(),
    String(event?.type || "").trim(),
    JSON.stringify(localLiuAgentRuntimeEventPayload(event)),
  ]
    .filter(Boolean)
    .join(":");
}

function markLocalLiuAgentRuntimeEventSeen(event = {}) {
  const eventKey = localLiuAgentRuntimeEventKey(event);
  if (!eventKey) return true;
  if (localLiuAgentSeenRuntimeEventIds.has(eventKey)) return false;
  localLiuAgentSeenRuntimeEventIds.add(eventKey);
  return true;
}

function handleNativeLiuAgentRuntimeEvent(event = {}) {
  const chatSessionId = String(event?.chat_session_id || event?.chatSessionId || "").trim();
  const run = localLiuAgentActiveRunForChatSession(chatSessionId);
  if (!run || run.cancelled) return;
  if (!markLocalLiuAgentRuntimeEventSeen(event)) return;
  const row = localLiuAgentActiveRunRow(run);
  if (!row) return;
  updateLocalLiuAgentRuntimeTimingFromEvent(row, event, {
    startedAt: run.startedAt,
  });
  const payload = localLiuAgentRuntimeEventPayload(event);
  const eventType = String(event?.type || "").trim();
  if (
    String(event?.type || "").trim() === "tool_result" &&
    String(payload?.error_code || payload?.errorCode || "").trim() ===
      "permission.required"
  ) {
    return;
  }
  if (["plan_created", "plan_updated", "plan_completed"].includes(eventType)) {
    applyLiuAgentPlanEvent(
      row,
      {
        run_id: String(
          event?.runtime_session_id || event?.runtimeSessionId || event?.run_id || "",
        ).trim(),
        event_type: eventType,
        event,
      },
      String(run.assistantMessageId || row.id || "").trim(),
    );
    scrollToBottom({ force: false });
    return;
  }
  applyLocalLiuAgentReasoningContent(row, event);
  const operation = localLiuAgentRuntimeEventOperation(event, {
    chatSessionId,
    workspacePath: run.workspacePath,
    assistantMessageId: run.assistantMessageId,
  });
  if (shouldUpsertLocalLiuAgentRuntimeOperation(event, operation)) {
    upsertMessageOperation(row, operation);
  }
  appendMessageProcessLog(row, {
    ...localLiuAgentRuntimeEventProcessLogEntry(event, operation),
    autoExpand: true,
  });
  scrollToBottom({ force: false });
}

function localLiuAgentRuntimeEventCreatedAt(event = {}) {
  const direct = Number(event?.created_at_epoch_ms || event?.createdAtEpochMs || 0) || 0;
  if (direct > 0) return direct;
  const payload = localLiuAgentRuntimeEventPayload(event);
  return Number(payload?.created_at_epoch_ms || payload?.createdAtEpochMs || 0) || 0;
}

function isLocalLiuAgentRuntimeEventForActiveRun(event = {}, run = {}) {
  const createdAt = localLiuAgentRuntimeEventCreatedAt(event);
  const startedAt = Number(run?.startedAt || 0) || 0;
  return !createdAt || !startedAt || createdAt >= startedAt - 100;
}

async function pollLocalLiuAgentRuntimeEventsOnce() {
  if (localLiuAgentRuntimeEventPollInFlight) return;
  if (!localLiuAgentActiveRuns.size) {
    stopLocalLiuAgentRuntimeEventPollingIfIdle();
    return;
  }
  localLiuAgentRuntimeEventPollInFlight = true;
  try {
    const runs = Array.from(localLiuAgentActiveRuns.entries());
    for (const [chatSessionId, run] of runs) {
      if (!run || run.cancelled) continue;
      const projectId = String(run.projectId || selectedProjectId.value || "").trim();
      const workspacePath = String(run.workspacePath || projectWorkspacePath.value || "").trim();
      if (!projectId || !chatSessionId || !workspacePath) continue;
      const result = await listNativeLiuAgentRuntimeEvents({
        projectId,
        chatSessionId,
        workspacePath,
        afterEventId: run.lastRuntimeEventId || "",
        limit: 120,
      });
      const events = Array.isArray(result?.events) ? result.events : [];
      for (const event of events) {
        const eventId = String(event?.event_id || event?.eventId || "").trim();
        if (eventId) run.lastRuntimeEventId = eventId;
        if (!isLocalLiuAgentRuntimeEventForActiveRun(event, run)) continue;
        handleNativeLiuAgentRuntimeEvent(event);
      }
    }
  } catch (err) {
    console.warn("poll local liuAgent runtime events failed", err);
  } finally {
    localLiuAgentRuntimeEventPollInFlight = false;
  }
}

function startLocalLiuAgentRuntimeEventPolling() {
  if (localLiuAgentRuntimeEventPollTimer || !hasNativeDesktopBridge()) return;
  localLiuAgentRuntimeEventPollTimer = window.setInterval(() => {
    void pollLocalLiuAgentRuntimeEventsOnce();
  }, 600);
  void pollLocalLiuAgentRuntimeEventsOnce();
}

function stopLocalLiuAgentRuntimeEventPollingIfIdle() {
  if (localLiuAgentActiveRuns.size > 0 || !localLiuAgentRuntimeEventPollTimer) return;
  window.clearInterval(localLiuAgentRuntimeEventPollTimer);
  localLiuAgentRuntimeEventPollTimer = null;
  localLiuAgentRuntimeEventPollInFlight = false;
}

async function startNativeLiuAgentRuntimeEventSubscription() {
  if (nativeLiuAgentRuntimeEventUnlisten || !hasNativeDesktopBridge()) return;
  nativeLiuAgentRuntimeEventUnlisten = await subscribeNativeLiuAgentRuntimeEvents(
    handleNativeLiuAgentRuntimeEvent,
  );
}

function stopNativeLiuAgentRuntimeEventSubscription() {
  const unlisten = nativeLiuAgentRuntimeEventUnlisten;
  nativeLiuAgentRuntimeEventUnlisten = null;
  if (typeof unlisten === "function") {
    try {
      const result = unlisten();
      if (result && typeof result.catch === "function") {
        result.catch(() => {});
      }
    } catch {
      // ignore cleanup errors
    }
  }
}

function localBotRunnerResultContent(result = {}) {
  return String(
    result?.assistantContent ||
      result?.assistant_content ||
      result?.summary ||
      result?.userVisibleErrorSummary ||
      result?.user_visible_error_summary ||
      result?.error ||
      "",
  ).trim();
}

function localBotRunnerPlainObject(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : {};
}

function localBotRunnerString(...values) {
  for (const value of values) {
    const normalized = String(value || "").trim();
    if (normalized) return normalized;
  }
  return "";
}

function findLocalBotConnectorForRequest(request = {}) {
  const connector = localBotRunnerPlainObject(request.connector);
  const connectorId = localBotRunnerString(
    connector.connectorId,
    connector.connector_id,
    request.connectorId,
    request.connector_id,
  );
  if (!connectorId) return null;
  return (botPlatformConnectors.value || []).find(
    (item) => String(item?.id || "").trim() === connectorId,
  ) || null;
}

async function buildLocalBotRunnerModelRuntime(request = {}) {
  const connector = localBotRunnerPlainObject(request.connector);
  const existingRuntime =
    request.modelRuntime && typeof request.modelRuntime === "object"
      ? request.modelRuntime
      : request.model_runtime && typeof request.model_runtime === "object"
        ? request.model_runtime
        : null;
  if (existingRuntime) return existingRuntime;

  const providerId = localBotRunnerString(
    request.providerId,
    request.provider_id,
    connector.providerId,
    connector.provider_id,
  );
  const requestedModelName = localBotRunnerString(
    request.modelName,
    request.model_name,
    connector.modelName,
    connector.model_name,
  );
  if (!providerId) return buildLocalLiuAgentModelRuntime();

  const runtime = await fetchLocalLiuAgentDesktopModelRuntime(providerId);
  const modelName = localBotRunnerString(
    requestedModelName,
    runtime.model_name,
    runtime.modelName,
    runtime.default_model,
    runtime.defaultModel,
  );
  if (!modelName) {
    throw new Error(`机器人模型供应商缺少可用模型名：${providerId}`);
  }
  return {
    mode: "direct-openai-compatible",
    providerId,
    modelName,
    baseUrl: String(runtime.base_url || runtime.baseUrl || "").trim(),
    apiKey: String(runtime.api_key || runtime.apiKey || "").trim(),
    temperature: Number(temperature.value ?? CHAT_SETTINGS_DEFAULTS.temperature),
  };
}

async function enrichLocalBotRunnerRequest(request = {}, workspacePath = "") {
  const normalizedRequest = localBotRunnerPlainObject(request);
  const localConnector = findLocalBotConnectorForRequest(normalizedRequest);
  const requestConnector = localBotRunnerPlainObject(normalizedRequest.connector);
  const connectorId = localBotRunnerString(
    requestConnector.connectorId,
    requestConnector.connector_id,
    normalizedRequest.connectorId,
    normalizedRequest.connector_id,
  );
  if (connectorId && !localConnector) {
    throw new Error(`本机全局机器人配置中找不到连接器：${connectorId}`);
  }
  if (localConnector) {
    normalizedRequest.connector = {
      ...requestConnector,
      connectorId: localConnector.id,
      connector_id: localConnector.id,
      platform: localConnector.platform,
      name: localConnector.name,
      systemPrompt: localConnector.system_prompt,
      system_prompt: localConnector.system_prompt,
      providerId: localConnector.provider_id,
      provider_id: localConnector.provider_id,
      modelName: localConnector.model_name,
      model_name: localConnector.model_name,
      replyIdentity: localConnector.reply_identity,
      reply_identity: localConnector.reply_identity,
      ownerUsername: localBotRunnerString(
        requestConnector.ownerUsername,
        requestConnector.owner_username,
        normalizedRequest.ownerUsername,
        normalizedRequest.owner_username,
        currentUsername.value,
      ),
      owner_username: localBotRunnerString(
        requestConnector.ownerUsername,
        requestConnector.owner_username,
        normalizedRequest.ownerUsername,
        normalizedRequest.owner_username,
        currentUsername.value,
      ),
      sandboxMode: localConnector.sandbox_mode,
      sandbox_mode: localConnector.sandbox_mode,
      highRiskToolConfirm: localConnector.high_risk_tool_confirm,
      high_risk_tool_confirm: localConnector.high_risk_tool_confirm,
    };
    normalizedRequest.providerId = localConnector.provider_id;
    normalizedRequest.provider_id = localConnector.provider_id;
    normalizedRequest.modelName = localConnector.model_name;
    normalizedRequest.model_name = localConnector.model_name;
  }
  const requestMcpConfig = localBotRunnerPlainObject(
    normalizedRequest.mcpConfig || normalizedRequest.mcp_config,
  );
  normalizedRequest.mcpConfig = mergeMcpConfigs(
    effectiveMcpConfig.value,
    requestMcpConfig,
  );
  if (!normalizedRequest.backendContext && !normalizedRequest.backend_context) {
    normalizedRequest.backendContext = {
      apiBaseUrl: buildLocalLiuAgentBackendApiBaseUrl(),
      token: getStoredToken(),
    };
  }
  if (!normalizedRequest.modelRuntime && !normalizedRequest.model_runtime) {
    normalizedRequest.modelRuntime =
      await buildLocalBotRunnerModelRuntime(normalizedRequest);
  }
  if (!normalizedRequest.permissionDecision && !normalizedRequest.permission_decision) {
    normalizedRequest.permissionDecision = localLiuAgentFullAccessEnabled()
      ? buildLocalLiuAgentPermissionDecision("", {}, { fullAccess: true })
      : null;
  }
  normalizedRequest.workspacePath = localBotRunnerString(
    normalizedRequest.workspacePath,
    normalizedRequest.workspace_path,
    workspacePath,
  );
  return normalizedRequest;
}

function localFeishuBotEventString(value, ...fallbacks) {
  for (const item of [value, ...fallbacks]) {
    const normalized = String(item || "").trim();
    if (normalized) return normalized;
  }
  return "";
}

function escapeRegExp(value) {
  return String(value || "").replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function localFeishuBotConnectorById(connectorId) {
  const normalizedId = String(connectorId || "").trim();
  if (!normalizedId) return null;
  return (botPlatformConnectors.value || []).find(
    (item) => String(item?.id || "").trim() === normalizedId,
  ) || null;
}

function parseLocalFeishuJsonObject(value) {
  if (value && typeof value === "object" && !Array.isArray(value)) return value;
  const text = String(value || "").trim();
  if (!text || !text.startsWith("{")) return {};
  try {
    const parsed = JSON.parse(text);
    return parsed && typeof parsed === "object" && !Array.isArray(parsed)
      ? parsed
      : {};
  } catch {
    return {};
  }
}

function normalizeLocalFeishuBotStatusMessage(message = "") {
  const raw = String(message || "").trim();
  if (!raw) return "";
  const parsed = parseLocalFeishuJsonObject(raw);
  const error = parsed?.error && typeof parsed.error === "object" ? parsed.error : {};
  const parts = [
    localFeishuBotEventString(error.message, parsed.message),
    localFeishuBotEventString(error.hint, parsed.hint),
  ].filter(Boolean);
  return (parts.length ? parts.join("；") : raw).replace(/\s+/g, " ").trim();
}

function localFeishuArray(...values) {
  for (const value of values) {
    if (Array.isArray(value)) return value;
  }
  return [];
}

function localFeishuSenderId(sender = {}) {
  if (!sender || typeof sender !== "object") return "";
  const senderId = sender.sender_id || sender.senderId || sender.id || {};
  if (senderId && typeof senderId === "object") {
    return localFeishuBotEventString(
      senderId.open_id,
      senderId.openId,
      senderId.user_id,
      senderId.userId,
      senderId.union_id,
      senderId.unionId,
    );
  }
  return localFeishuBotEventString(senderId);
}

function normalizeLocalFeishuBotEvent(rawEvent = {}) {
  const root = rawEvent && typeof rawEvent === "object" ? rawEvent : {};
  const event = root.event && typeof root.event === "object" ? root.event : root;
  const message =
    event.message && typeof event.message === "object" ? event.message : event;
  const sender =
    event.sender && typeof event.sender === "object"
      ? event.sender
      : message.sender && typeof message.sender === "object"
        ? message.sender
        : {};
  const rawContent = localFeishuBotEventString(
    message.content,
    event.content,
    root.content,
  );
  const parsedContent = parseLocalFeishuJsonObject(rawContent);
  const text = localFeishuBotEventString(
    parsedContent.text,
    parsedContent.content,
    message.text,
    event.text,
    root.text,
    rawContent.startsWith("{") ? "" : rawContent,
  );
  const mentions = localFeishuArray(
    message.mentions,
    event.mentions,
    root.mentions,
    parsedContent.mentions,
    message.message_mentions,
    event.message_mentions,
    root.message_mentions,
  );
  return {
    ...root,
    ...event,
    ...message,
    content: text,
    text,
    raw_content: rawContent,
    parsed_content: parsedContent,
    mentions,
    message_mentions: mentions,
    message_id: localFeishuBotEventString(
      message.message_id,
      message.messageId,
      event.message_id,
      event.messageId,
      root.message_id,
      root.messageId,
      root.id,
    ),
    event_id: localFeishuBotEventString(
      root.event_id,
      root.eventId,
      event.event_id,
      event.eventId,
      message.message_id,
      message.messageId,
    ),
    chat_id: localFeishuBotEventString(
      message.chat_id,
      message.chatId,
      event.chat_id,
      event.chatId,
      root.chat_id,
      root.chatId,
    ),
    chat_type: localFeishuBotEventString(
      message.chat_type,
      message.chatType,
      event.chat_type,
      event.chatType,
      root.chat_type,
      root.chatType,
    ),
    chat_name: localFeishuBotEventString(
      message.chat_name,
      message.chatName,
      event.chat_name,
      event.chatName,
      root.chat_name,
      root.chatName,
    ),
    thread_id: localFeishuBotEventString(
      message.thread_id,
      message.threadId,
      event.thread_id,
      event.threadId,
      root.thread_id,
      root.threadId,
    ),
    sender_id: localFeishuSenderId(sender),
    raw_event: root,
  };
}

function handleNativeFeishuLocalBotStatus(payload = {}) {
  const connectorId = localFeishuBotEventString(
    payload.connectorId,
    payload.connector_id,
  );
  if (!connectorId) return;
  const state = localFeishuBotEventString(payload.state, "log");
  const message = normalizeLocalFeishuBotStatusMessage(
    localFeishuBotEventString(payload.message),
  );
  localFeishuBotStatuses.value = {
    ...(localFeishuBotStatuses.value || {}),
    [connectorId]: {
      state,
      message,
      updatedAt: new Date().toISOString(),
    },
  };
  if (["error", "exited"].includes(state)) {
    localFeishuBotListenerIds.delete(connectorId);
    const warningKey = `${connectorId}:${state}:${message}`;
    if (!localFeishuBotStatusWarningKeys.has(warningKey)) {
      localFeishuBotStatusWarningKeys.add(warningKey);
      ElMessage.warning(message ? `飞书机器人监听${state === "exited" ? "已退出" : "失败"}：${message}` : "飞书机器人监听失败");
    }
  }
}

function normalizeLocalFeishuBotMessage(connector, event = {}) {
  let content = localFeishuBotEventString(event.content, event.text, event.message);
  const names = [
    connector?.name,
    connector?.agent_name,
    connector?.id,
  ]
    .map((item) => String(item || "").trim())
    .filter(Boolean);
  for (const name of names) {
    content = content
      .replace(new RegExp(`^@?${escapeRegExp(name)}[\\s:：,，]*`, "i"), "")
      .trim();
  }
  return content;
}

function localFeishuBotMentionedByEvent(event = {}) {
  const mentions = Array.isArray(event.mentions)
    ? event.mentions
    : Array.isArray(event.message_mentions)
      ? event.message_mentions
      : [];
  return mentions.some((mention) => {
    const type = String(mention?.type || mention?.mention_type || "").toLowerCase();
    return type.includes("bot") || type.includes("app");
  });
}

function shouldHandleLocalFeishuBotEvent(connector, event = {}) {
  if (!connector || connector.enabled === false) return false;
  if (String(connector.platform || "").trim().toLowerCase() !== "feishu") return false;
  const chatType = String(event.chat_type || event.chatType || "").trim().toLowerCase();
  if (chatType === "p2p") return true;
  if (localFeishuBotMentionedByEvent(event)) return true;
  const content = localFeishuBotEventString(event.content, event.text, event.message);
  const mentionTargets = [
    connector.name,
    connector.agent_name,
    connector.id,
  ]
    .map((item) => String(item || "").trim())
    .filter(Boolean);
  return mentionTargets.some((target) =>
    content.toLowerCase().includes(target.toLowerCase()),
  );
}

function resolveLocalFeishuBotBoundSessionId(connector, event = {}) {
  const chatId = localFeishuBotEventString(event.chat_id, event.chatId);
  const connectorId = String(connector?.id || "").trim();
  if (!chatId || !connectorId) return "";
  const matched = (chatSessions.value || []).find((session) => {
    const source = normalizeChatSourceContext(session || {});
    return (
      String(source.platform || "").trim().toLowerCase() === "feishu" &&
      String(source.connector_id || source.connectorId || "").trim() === connectorId &&
      String(source.external_chat_id || source.externalChatId || "").trim() === chatId
    );
  });
  return String(matched?.id || "").trim();
}

async function ensureLocalFeishuBotChatSession(connector, event = {}) {
  const existing = resolveLocalFeishuBotBoundSessionId(connector, event);
  if (existing) return existing;
  const chatId = localFeishuBotEventString(event.chat_id, event.chatId);
  if (!chatId) return String(currentChatSessionId.value || "").trim();
  const sourceContext = {
    platform: "feishu",
    connector_id: String(connector?.id || "").trim(),
    connector_name: String(connector?.name || "").trim(),
    external_chat_id: chatId,
    external_chat_name: localFeishuBotEventString(
      event.chat_name,
      event.chatName,
      chatId,
    ),
    source_type:
      String(event.chat_type || "").trim().toLowerCase() === "p2p"
        ? "private_message"
        : "group_message",
  };
  const created = await createChatSession({
    switchTo: false,
    title: sourceContext.external_chat_name || `${connector?.name || "飞书"}机器人对话`,
    sourceContext,
  });
  return String(created?.id || "").trim();
}

function collectLocalFeishuResourceRefs(value, refs = []) {
  if (!value || refs.length >= 8) return refs;
  if (Array.isArray(value)) {
    for (const item of value) collectLocalFeishuResourceRefs(item, refs);
    return refs;
  }
  if (typeof value === "string") {
    const parsed = parseLocalFeishuJsonObject(value);
    if (Object.keys(parsed).length) {
      collectLocalFeishuResourceRefs(parsed, refs);
    }
    const matches = value.match(/\b(?:img|file)_[A-Za-z0-9._-]+\b/g) || [];
    for (const fileKey of matches) {
      if (refs.length >= 8) break;
      if (refs.some((item) => item.fileKey === fileKey)) continue;
      refs.push({
        fileKey,
        resourceType: /^file_/i.test(fileKey) ? "file" : "image",
        label: fileKey,
      });
    }
    return refs;
  }
  if (typeof value !== "object") return refs;
  const fileKey = localFeishuBotEventString(
    value.file_key,
    value.fileKey,
    value.image_key,
    value.imageKey,
    value.key,
  );
  if (fileKey && /^(img|file)_/i.test(fileKey)) {
    const resourceType =
      String(value.type || value.resource_type || value.resourceType || "")
        .toLowerCase()
        .includes("file") || /^file_/i.test(fileKey)
        ? "file"
        : "image";
    if (!refs.some((item) => item.fileKey === fileKey)) {
      refs.push({
        fileKey,
        resourceType,
        label: localFeishuBotEventString(value.name, value.label, fileKey),
      });
    }
  }
  for (const item of Object.values(value)) {
    collectLocalFeishuResourceRefs(item, refs);
  }
  return refs;
}

async function enrichLocalFeishuBotEventForResources(
  event = {},
  messageId = "",
  identity = "bot",
) {
  if (collectLocalFeishuResourceRefs(event).length || !messageId) {
    return event;
  }
  try {
    const result = await getNativeFeishuMessage({
      messageId,
      identity,
      downloadResources: true,
    });
    const payload = result?.payload && typeof result.payload === "object"
      ? result.payload
      : {};
    return {
      ...event,
      message_detail: payload,
    };
  } catch (error) {
    console.warn("fetch feishu message detail for resources failed", error);
    return event;
  }
}

function dataUrlMimeType(dataUrl = "") {
  const matched = String(dataUrl || "").match(/^data:([^;,]+)[;,]/);
  return matched?.[1] || "";
}

async function buildLocalFeishuBotAttachments(event = {}, messageId = "", identity = "bot") {
  const eventWithDetail = await enrichLocalFeishuBotEventForResources(
    event,
    messageId,
    identity,
  );
  const refs = collectLocalFeishuResourceRefs(eventWithDetail);
  const attachments = [];
  for (const [index, ref] of refs.entries()) {
    try {
      const result = await downloadNativeFeishuMessageResource({
        messageId,
        fileKey: ref.fileKey,
        resourceType: ref.resourceType,
        identity,
      });
      const dataUrl = String(result?.dataUrl || result?.data_url || "").trim();
      const name = String(result?.name || ref.label || ref.fileKey).trim();
      attachments.push({
        attachmentId: `feishu_${messageId}_${index}`,
        name,
        mimeType: dataUrlMimeType(dataUrl),
        size: Number(result?.size || 0) || 0,
        kind: ref.resourceType === "image" ? "image" : "file",
        routingMode: ref.resourceType === "image" ? "inline_image" : "local_extract",
        extractionStatus: dataUrl ? "image_data_url" : "metadata_only",
        dataUrl,
        extractedText: String(result?.localPath || result?.local_path || "").trim()
          ? `飞书资源已下载到本机：${String(result?.localPath || result?.local_path || "").trim()}`
          : "",
        providerFileId: "",
        error: "",
      });
    } catch (error) {
      attachments.push({
        attachmentId: `feishu_${messageId}_${index}`,
        name: ref.label || ref.fileKey,
        mimeType: "",
        size: 0,
        kind: ref.resourceType,
        routingMode: "local_extract",
        extractionStatus: "error",
        dataUrl: "",
        extractedText: "",
        providerFileId: "",
        error: error?.message || "飞书资源下载失败",
      });
    }
  }
  return attachments;
}

async function handleNativeFeishuLocalBotEvent(payload = {}) {
  const rawEvent = payload?.event && typeof payload.event === "object" ? payload.event : {};
  const event = normalizeLocalFeishuBotEvent(rawEvent);
  const connectorId = localFeishuBotEventString(
    payload.connectorId,
    payload.connector_id,
    event.connector_id,
  );
  const connector = localFeishuBotConnectorById(connectorId);
  const eventId = localFeishuBotEventString(event.event_id, event.message_id, event.id);
  const eventKey = `${connectorId}:${eventId || JSON.stringify(event).slice(0, 160)}`;
  if (!connector || localFeishuBotProcessingEventIds.has(eventKey)) return;
  if (!shouldHandleLocalFeishuBotEvent(connector, event)) return;

  const projectId = localFeishuBotEventString(payload.projectId, selectedProjectId.value);
  const chatSessionId = await ensureLocalFeishuBotChatSession(connector, event);
  const workspacePath = localFeishuBotEventString(
    payload.workspacePath,
    localLiuAgentWorkspacePath(),
  );
  const message = normalizeLocalFeishuBotMessage(connector, event);
  const messageId = localFeishuBotEventString(event.message_id, event.id);
  if (!projectId || !chatSessionId || !workspacePath || !message || !messageId) return;

  localFeishuBotProcessingEventIds.add(eventKey);
  try {
    const attachments = await buildLocalFeishuBotAttachments(
      event,
      messageId,
      connector.reply_identity || "bot",
    );
    const request = {
      projectId,
      chatSessionId,
      messageId,
      assistantMessageId: `bot-local-${Date.now().toString(36)}`,
      message,
      workspacePath,
      connector: {
        connectorId: connector.id,
        platform: connector.platform,
        name: connector.name,
        systemPrompt: connector.system_prompt,
        providerId: connector.provider_id,
        modelName: connector.model_name,
        replyIdentity: connector.reply_identity,
        ownerUsername: String(currentUsername.value || "").trim(),
        sandboxMode: connector.sandbox_mode,
        highRiskToolConfirm: connector.high_risk_tool_confirm,
      },
      attachments,
      sourceContext: {
        source_type:
          String(event.chat_type || "").trim().toLowerCase() === "p2p"
            ? "private_message"
            : "group_message",
        platform: "feishu",
        connector_id: connector.id,
        external_chat_id: localFeishuBotEventString(event.chat_id),
        external_chat_name: localFeishuBotEventString(event.chat_name, event.chatName),
        external_message_id: messageId,
        sender_id: localFeishuBotEventString(event.sender_id),
        chat_type: localFeishuBotEventString(event.chat_type),
        runtime_migration_status: "desktop_frontend_local_listener",
        execution_authority: "delegated_user_desktop_runner",
        raw: rawEvent,
      },
      mcpConfig: effectiveMcpConfig.value,
    };
    const result = await startNativeBotLocalChat(
      await enrichLocalBotRunnerRequest(request, workspacePath),
    );
    const replyContent = localBotRunnerResultContent(result);
    if (replyContent) {
      await replyNativeFeishuBotMessage({
        messageId,
        content: replyContent,
        contentFormat: "markdown",
        replyIdentity: connector.reply_identity || "bot",
        replyInThread: Boolean(event.thread_id || event.threadId),
        idempotencyKey: `desktop-bot-reply-${messageId}`,
      });
    }
  } catch (error) {
    console.warn("handle local feishu bot event failed", error);
  } finally {
    window.setTimeout(() => {
      localFeishuBotProcessingEventIds.delete(eventKey);
    }, 60_000);
  }
}

async function syncLocalFeishuBotListeners() {
  if (!hasNativeDesktopBridge()) return;
  const runtimeInfo = await getNativeRuntimeInfo().catch(() => null);
  const workspacePath = String(
    runtimeInfo?.defaultWorkspacePath ||
      runtimeInfo?.default_workspace_path ||
      localLiuAgentWorkspacePath() ||
      "",
  ).trim();
  const contextKey = ["desktop-bot-global", workspacePath].join("|");
  if (
    localFeishuBotListenerContextKey &&
    localFeishuBotListenerContextKey !== contextKey
  ) {
    for (const connectorId of Array.from(localFeishuBotListenerIds)) {
      try {
        await stopNativeFeishuLocalBotListener(connectorId);
      } catch (error) {
        console.warn("restart local feishu bot listener failed", error);
      }
    }
    localFeishuBotListenerIds.clear();
  }
  localFeishuBotListenerContextKey = contextKey;

  if (!localFeishuBotStatusUnlisten) {
    localFeishuBotStatusUnlisten =
      await subscribeNativeFeishuLocalBotStatus(handleNativeFeishuLocalBotStatus);
  }

  const enabledConnectorIds = new Set(
    (botPlatformConnectors.value || [])
      .filter((connector) => {
        return (
          connector?.enabled !== false &&
          connector?.auto_start_worker === true &&
          String(connector?.platform || "").trim().toLowerCase() === "feishu" &&
          String(connector?.event_receive_mode || "").trim().toLowerCase() === "long_connection" &&
          String(connector?.id || "").trim()
        );
      })
      .map((connector) => String(connector.id).trim()),
  );

  for (const connectorId of Array.from(localFeishuBotListenerIds)) {
    if (enabledConnectorIds.has(connectorId)) continue;
    try {
      await stopNativeFeishuLocalBotListener(connectorId);
    } catch (error) {
      console.warn("stop local feishu bot listener failed", error);
    } finally {
      localFeishuBotListenerIds.delete(connectorId);
    }
  }

  for (const connectorId of enabledConnectorIds) {
    if (localFeishuBotListenerIds.has(connectorId)) continue;
    try {
      const connector = localFeishuBotConnectorById(connectorId);
      const modelRuntime = await buildLocalBotRunnerModelRuntime({ connector });
      await startNativeFeishuLocalBotListener({
        connectorId,
        workspacePath,
        ownerUsername: currentUsername.value,
        modelRuntime,
        mcpConfig: globalMcpConfig.value,
        backendContext: {
          apiBaseUrl: buildLocalLiuAgentBackendApiBaseUrl(),
          token: getStoredToken(),
        },
        permissionDecision: localLiuAgentFullAccessEnabled()
          ? buildLocalLiuAgentPermissionDecision("", {}, { fullAccess: true })
          : null,
      });
      localFeishuBotListenerIds.add(connectorId);
    } catch (error) {
      console.warn("start local feishu bot listener failed", error);
    }
  }
}

function localLiuAgentUserMessageFromRuntimeEvents(events = []) {
  const event = (Array.isArray(events) ? events : []).find((item) => {
    const payload = localLiuAgentRuntimeEventPayload(item);
    return (
      String(item?.type || "").trim() === "message" &&
      String(payload?.role || "").trim() === "user" &&
      String(payload?.content || "").trim()
    );
  });
  if (!event) return null;
  const payload = localLiuAgentRuntimeEventPayload(event);
  return {
    messageId: String(payload?.message_id || payload?.messageId || "").trim(),
    content: String(payload?.content || "").trim(),
  };
}

function localLiuAgentAssistantMessageIdFromRuntimeEvents(events = []) {
  const event = (Array.isArray(events) ? events : []).find((item) => {
    const payload = localLiuAgentRuntimeEventPayload(item);
    return (
      String(item?.type || "").trim() === "message" &&
      String(payload?.role || "").trim() === "assistant" &&
      String(payload?.message_id || payload?.messageId || "").trim()
    );
  });
  const payload = event ? localLiuAgentRuntimeEventPayload(event) : {};
  return String(payload?.message_id || payload?.messageId || "").trim();
}

function localLiuAgentPendingPermissionFromRecovery(result = {}) {
  const state = result?.state && typeof result.state === "object" ? result.state : {};
  const runState =
    state?.run_state && typeof state.run_state === "object" ? state.run_state : {};
  const pendingPermissions = Array.isArray(runState?.pending_permissions)
    ? runState.pending_permissions
    : [];
  const permission = pendingPermissions.find((item) => {
    const requestId = String(item?.requestId || item?.request_id || "").trim();
    return Boolean(requestId);
  });
  if (permission) return permission;
  for (const event of localLiuAgentRuntimeEventsFromResult(result)) {
    if (String(event?.type || "").trim() !== "approval_required") continue;
    const payload = localLiuAgentRuntimeEventPayload(event);
    const requestId = String(payload?.requestId || payload?.request_id || "").trim();
    if (requestId) return payload;
  }
  return null;
}

function localLiuAgentRuntimeSessionIdFromRecovery(result = {}) {
  const state = result?.state && typeof result.state === "object" ? result.state : {};
  return String(state?.session_id || state?.sessionId || "").trim();
}

function rowHasLocalLiuAgentRuntimeSession(row = {}, runtimeSessionId = "") {
  const normalizedSessionId = String(runtimeSessionId || "").trim();
  if (!row || !normalizedSessionId) return false;
  return (Array.isArray(row.operations) ? row.operations : []).some((operation) => {
    const meta =
      operation?.meta && typeof operation.meta === "object" ? operation.meta : {};
    return (
      String(meta.session_id || meta.sessionId || "").trim() === normalizedSessionId ||
      String(meta.runtime_session_id || meta.runtimeSessionId || "").trim() ===
        normalizedSessionId
    );
  });
}

function findLocalLiuAgentRuntimeMessage(rows = [], result = {}) {
  const normalizedRows = Array.isArray(rows) ? rows : messages.value;
  const runtimeEvents = localLiuAgentRuntimeEventsFromResult(result);
  const assistantMessageId =
    localLiuAgentAssistantMessageIdFromRuntimeEvents(runtimeEvents);
  if (assistantMessageId) {
    return (
      normalizedRows.find(
        (item) => String(item?.id || "").trim() === assistantMessageId,
      ) || null
    );
  }
  const runtimeSessionId = localLiuAgentRuntimeSessionIdFromRecovery(result);
  if (runtimeSessionId) {
    return (
      normalizedRows.find(
        (item) =>
          item &&
          item.role !== "user" &&
          rowHasLocalLiuAgentRuntimeSession(item, runtimeSessionId),
      ) || null
    );
  }
  return null;
}

function localLiuAgentBackgroundJobsFromRecovery(result = {}) {
  const state = result?.state && typeof result.state === "object" ? result.state : {};
  const jobs = Array.isArray(state?.background_jobs) ? state.background_jobs : [];
  return jobs.filter((job) => job && typeof job === "object");
}

function localLiuAgentResumeJudgementFromRecovery(result = {}) {
  const state = result?.state && typeof result.state === "object" ? result.state : {};
  return state?.resume_judgement && typeof state.resume_judgement === "object"
    ? state.resume_judgement
    : null;
}

function localLiuAgentBackgroundJobStatusLabel(status) {
  const normalized = String(status || "")
    .trim()
    .toLowerCase();
  if (normalized === "running") return "仍在执行";
  if (normalized === "succeeded") return "已完成，等待 AI 验证";
  if (normalized === "failed") return "执行失败，等待 AI 判断";
  if (normalized === "cancelled") return "已取消";
  return "状态未知";
}

function localLiuAgentResumeJudgementLabel(decision) {
  const normalized = String(decision || "")
    .trim()
    .toLowerCase();
  if (normalized === "continue_waiting") return "任务还在进行中，可以继续等待或刷新状态";
  if (normalized === "ask_ai_to_verify_completion") return "命令已结束，需要让 AI 根据产物和日志确认是否完成目标";
  if (normalized === "ask_ai_to_inspect_failure") return "命令失败，需要让 AI 读取日志判断失败原因";
  if (normalized === "ask_ai_to_judge") return "当前没有足够信号，需要 AI 检查上下文再判断下一步";
  return "";
}

function localLiuAgentBackgroundJobDetail(job = {}, judgement = null) {
  const lines = [];
  const cmd = String(job?.cmd || "").trim();
  const cwd = String(job?.cwd || "").trim();
  const pid = String(job?.pid || "").trim();
  const exitCode =
    job?.exit_code !== undefined && job?.exit_code !== null
      ? String(job.exit_code).trim()
      : "";
  if (cmd) lines.push(`命令：${cmd}`);
  if (cwd) lines.push(`目录：${cwd}`);
  if (pid) lines.push(`PID：${pid}`);
  if (exitCode) lines.push(`退出码：${exitCode}`);
  const decisionText = localLiuAgentResumeJudgementLabel(judgement?.decision);
  if (decisionText) lines.push(`判断：${decisionText}`);
  const stdoutPath = String(job?.stdout_log_path || "").trim();
  const stderrPath = String(job?.stderr_log_path || "").trim();
  if (stdoutPath) lines.push(`stdout：${stdoutPath}`);
  if (stderrPath) lines.push(`stderr：${stderrPath}`);
  return lines.join("\n");
}

function upsertLocalLiuAgentBackgroundJobOperation(row, job = {}, options = {}) {
  if (!row || !job || typeof job !== "object") return false;
  const statePath = String(job?.state_path || "").trim();
  const jobId = String(job?.job_id || statePath || "").trim();
  if (!jobId || !statePath) return false;
  const status = String(job?.status || "unknown")
    .trim()
    .toLowerCase();
  const judgement =
    options?.judgement && typeof options.judgement === "object"
      ? options.judgement
      : null;
  const phase =
    status === "running"
      ? "running"
      : status === "succeeded"
        ? "blocked"
        : status === "failed"
          ? "blocked"
          : status === "cancelled"
            ? "blocked"
            : "blocked";
  upsertMessageOperation(row, {
    operationId: `local-agent-background-job:${jobId}`,
    kind: "tool",
    title: "后台任务状态",
    summary: localLiuAgentBackgroundJobStatusLabel(status),
    detail: localLiuAgentBackgroundJobDetail(job, judgement),
    phase,
    actionType: "none",
    meta: {
      local_liuagent_background_job: "true",
      job,
      state_path: statePath,
      job_id: jobId,
      status,
      judgement,
      chat_session_id: String(options?.chatSessionId || currentChatSessionId.value || "").trim(),
      cwd: String(options?.workspacePath || localLiuAgentWorkspacePath() || "").trim(),
    },
  });
  row.processExpanded = true;
  return true;
}

function applyLocalLiuAgentBackgroundJobs(row, result = {}, options = {}) {
  const jobs = localLiuAgentBackgroundJobsFromRecovery(result);
  if (!row || !jobs.length) return false;
  const judgement = localLiuAgentResumeJudgementFromRecovery(result);
  let changed = false;
  jobs.forEach((job) => {
    changed =
      upsertLocalLiuAgentBackgroundJobOperation(row, job, {
        ...options,
        judgement,
      }) || changed;
  });
  return changed;
}

async function restoreLocalLiuAgentRuntimeState(projectId, chatSessionId, rows = []) {
  const activeProjectId = String(selectedProjectId.value || "").trim();
  const activeChatSessionId = String(currentChatSessionId.value || "").trim();
  if (
    String(projectId || "").trim() !== activeProjectId ||
    String(chatSessionId || "").trim() !== activeChatSessionId
  ) {
    return;
  }
  const workspacePath = localLiuAgentWorkspacePath();
  if (!workspacePath || !hasNativeDesktopBridge()) return;
  let result = null;
  try {
    result = await recoverNativeLiuAgentRuntimeState({
      projectId: activeProjectId,
      chatSessionId: activeChatSessionId,
      workspacePath,
    });
  } catch (err) {
    console.warn("recover local liuAgent runtime failed", err);
    return;
  }
  if (!result?.ok) {
    const code = String(result?.errorCode || result?.error_code || "").trim();
    if (code && code !== "state.not_found") {
      console.warn("recover local liuAgent runtime failed", result);
    }
    return;
  }
  const state = result?.state && typeof result.state === "object" ? result.state : {};
  const runState =
    state?.run_state && typeof state.run_state === "object" ? state.run_state : {};
  const status = String(runState?.status || "").trim();
  const backgroundJobs = localLiuAgentBackgroundJobsFromRecovery(result);
  const resumeJudgement = localLiuAgentResumeJudgementFromRecovery(result);
  const resumeDecision = String(resumeJudgement?.decision || "")
    .trim()
    .toLowerCase();
  if (
    !["waiting_approval", "failed"].includes(status) &&
    !backgroundJobs.length &&
    !["continue_waiting", "ask_ai_to_verify_completion", "ask_ai_to_inspect_failure", "ask_ai_to_judge"].includes(
      resumeDecision,
    )
  )
    return;
  const row = findLocalLiuAgentRuntimeMessage(rows, result);
  if (!row) return;
  applyLocalLiuAgentRuntimeEvents(row, result, {
    chatSessionId: activeChatSessionId,
    workspacePath,
  });
  applyLocalLiuAgentBackgroundJobs(row, result, {
    chatSessionId: activeChatSessionId,
    workspacePath,
  });
  if (status === "waiting_approval") {
    const permissionRequest = localLiuAgentPendingPermissionFromRecovery(result);
    const requestId = String(
      permissionRequest?.requestId || permissionRequest?.request_id || "",
    ).trim();
    const userMessage = localLiuAgentUserMessageFromRuntimeEvents(
      localLiuAgentRuntimeEventsFromResult(result),
    );
    if (!permissionRequest || !requestId || !userMessage?.content) return;
    let modelRuntime = null;
    try {
      modelRuntime = await buildLocalLiuAgentModelRuntime();
    } catch (_error) {
      modelRuntime = null;
    }
    const assistantMessageId =
      localLiuAgentAssistantMessageIdFromRuntimeEvents(
        localLiuAgentRuntimeEventsFromResult(result),
      ) || row.id;
    const localChatPayload = {
      projectId: activeProjectId,
      chatSessionId: activeChatSessionId,
      messageId: userMessage.messageId,
      assistantMessageId,
      message: userMessage.content,
      workspacePath,
      history: [],
      providerId: selectedProviderId.value || defaultProviderId.value || "",
      modelName: selectedModelName.value || defaultModelName.value || "",
      systemPrompt: buildLocalLiuAgentSystemPrompt(),
      systemPromptParts: buildLocalLiuAgentSystemPromptParts(),
      temperature: Number(temperature.value ?? CHAT_SETTINGS_DEFAULTS.temperature),
      modelRuntime,
      aiEntryFile: String(projectAiEntryFile.value || "").trim(),
      mcpConfig: effectiveMcpConfig.value,
    };
    const normalizedPermissionRequest = {
      ...permissionRequest,
      requestId,
      toolName:
        String(permissionRequest?.toolName || permissionRequest?.tool_name || "").trim() ||
        "本地工具",
    };
    setLocalLiuAgentPendingPermission(requestId, {
      kind: "local_chat",
      localChatPayload,
      permissionRequest: normalizedPermissionRequest,
      assistantMessageId: row.id,
      userMessageId: userMessage.messageId,
      activeChatSessionId,
      displayUserMessageContent: userMessage.content,
      finalUserPrompt: userMessage.content,
      sourceContext: {
        restored_from_local_runtime_state: true,
      },
    });
    appendMessageProcessLog(row, {
      text: "已恢复上次待授权的本地 liuAgent 会话",
      level: "warning",
    });
  } else if (status === "failed") {
    const hasNoSignal =
      resumeDecision === "continue_waiting" ||
      resumeDecision === "ask_ai_to_judge" ||
      backgroundJobs.some(
        (job) =>
          String(job?.status || "")
            .trim()
            .toLowerCase() === "running",
      );
    upsertMessageOperation(row, {
      operationId: `local-agent:${row.id}`,
      kind: "request",
      title: "桌面本地 Agent Runtime",
      summary: hasNoSignal
        ? "已恢复上次暂无信号的本地会话"
        : "已恢复上次失败的本地会话",
      detail:
        localLiuAgentResumeJudgementLabel(resumeDecision) ||
        String(result?.summary || result?.error || "").trim(),
      phase: hasNoSignal ? "blocked" : "failed",
      actionType: "none",
      meta: {
        local_liuagent_operation: "true",
        source: "tauri_liuagent_local_chat",
        chat_session_id: activeChatSessionId,
        cwd: workspacePath,
        resume_judgement: resumeJudgement,
      },
    });
    row.content =
      String(row.content || "").trim() ||
      (hasNoSignal
        ? "已恢复上次暂无信号的本地 liuAgent 会话。当前不能直接判断失败，请刷新后台任务状态或让 AI 继续检查。"
        : "已恢复上次失败的本地 liuAgent 会话，请检查执行过程后重新发送。");
  } else if (backgroundJobs.length) {
    const label = localLiuAgentResumeJudgementLabel(resumeDecision);
    if (label) {
      appendMessageProcessLog(row, {
        text: label,
        level: resumeDecision === "continue_waiting" ? "info" : "warning",
      });
    }
  }
  rememberChatSessionMessages(activeProjectId, activeChatSessionId, messages.value);
  schedulePersistChatRuntime();
}

function hasLiveTerminalOperation(row) {
  return (Array.isArray(row?.operations) ? row.operations : []).some(
    (operation) => isLiveTerminalOperation(operation),
  );
}

function hasActiveTerminalTransport() {
  return Boolean(
    terminalMirrorConnected.value || terminalPanelStatus.value === "running",
  );
}

function markTerminalOperationsWaitingForInput(
  row,
  summary = "等待你在对话框继续终端登录操作",
) {
  if (!row || !Array.isArray(row.operations) || !row.operations.length) {
    return false;
  }
  let changed = false;
  row.operations = row.operations.map((operation) => {
    if (!isLiveTerminalOperation(operation)) return operation;
    changed = true;
    return {
      ...operation,
      title: "需要你继续操作",
      phase: "waiting_user",
      actionType: "enter_text",
      summary: String(operation?.summary || summary).trim() || summary,
      detail:
        String(operation?.detail || "").trim() ||
        "终端会话仍在等待输入，主输入框会继续发送到项目终端。",
      updatedAt: nowText(),
    };
  });
  return changed;
}

function shouldPreserveTerminalInteractionAfterDone(row, pending) {
  const assistantIndex = Number(pending?.assistantIndex ?? -1);
  if (!row || assistantIndex < 0) return false;
  const activeIndex = Number(activeTerminalMirrorAssistantIndex.value ?? -1);
  if (activeIndex !== assistantIndex) return false;
  const hasLiveSession = hasActiveTerminalTransport();
  if (!hasLiveSession) return false;
  const interaction = terminalStructuredInteraction.value;
  const hasStructuredInteraction = Boolean(
    interaction && Number(interaction.assistantIndex) === assistantIndex,
  );
  const submissionHint = terminalStructuredSubmissionHint.value;
  const hasSubmittedStructuredInteraction = Boolean(
    submissionHint && Number(submissionHint.assistantIndex) === assistantIndex,
  );
  return Boolean(
    hasStructuredInteraction ||
    hasSubmittedStructuredInteraction ||
    hasLiveTerminalOperation(row) ||
    String(row.displayMode || "").trim() === "terminal",
  );
}

function findLatestTerminalInputAssistantIndex(rows) {
  for (let index = (rows || []).length - 1; index >= 0; index -= 1) {
    if (isTerminalInputCandidateRow(rows[index])) return index;
  }
  return -1;
}

const latestTerminalInputAssistantIndex = computed(() =>
  findLatestTerminalInputAssistantIndex(messages.value),
);

const activeTerminalInputTargetIndex = computed(() => {
  const activeIndex = Number(activeTerminalMirrorAssistantIndex.value ?? -1);
  const activeRow =
    activeIndex >= 0 && activeIndex < messages.value.length
      ? messages.value[activeIndex]
      : null;
  if (isTerminalInputCandidateRow(activeRow)) {
    return activeIndex;
  }
  return Number(latestTerminalInputAssistantIndex.value ?? -1);
});

function ensureActiveTerminalInputTarget() {
  const fallbackIndex = Number(activeTerminalInputTargetIndex.value ?? -1);
  if (fallbackIndex >= 0) {
    activeTerminalMirrorAssistantIndex.value = fallbackIndex;
  }
  return fallbackIndex;
}

const hasLiveTerminalSession = computed(() => {
  if (!String(selectedProjectId.value || "").trim()) return false;
  return hasActiveTerminalTransport();
});
const activePendingInteraction = computed(() => {
  const requestId = getActiveRequestId();
  if (requestId) {
    const pending = pendingRequests.get(requestId);
    if (!pending) return null;
    const row = messages.value[pending.assistantIndex];
    const operation = pickAwaitingInteractionOperation(row, {
      allowTerminal: true,
    });
    if (!row || !operation) return null;
    return {
      requestId,
      pending,
      row,
      operation,
    };
  }
  const restorable = findLatestAwaitingInteractionMessage(messages.value);
  if (!restorable?.row || !restorable?.operation) return null;
  return {
    requestId: "",
    pending: null,
    row: restorable.row,
    operation: restorable.operation,
  };
});
const isAwaitingUserInteraction = computed(() =>
  Boolean(activePendingInteraction.value?.operation),
);
const isAwaitingCardActionInteraction = computed(() => {
  const operation = activePendingInteraction.value?.operation;
  if (!operation) return false;
  if (canSupersedePendingInteraction(activePendingInteraction.value)) {
    return false;
  }
  return operationActionButtons(operation).length > 0;
});
const isTerminalInteractionMode = computed(() => {
  if (!String(selectedProjectId.value || "").trim()) return false;
  if (
    hasLiveTerminalSession.value &&
    activeTerminalInputTargetIndex.value >= 0
  ) {
    return true;
  }
  if (!String(activePendingInteraction.value?.requestId || "").trim()) {
    return false;
  }
  if (canSupersedePendingInteraction(activePendingInteraction.value)) {
    return false;
  }
  const operation = activePendingInteraction.value?.operation;
  if (operation) {
    const actionType = normalizeOperationActionType(operation?.actionType);
    const kind = String(operation?.kind || "")
      .trim()
      .toLowerCase();
    if (actionType === "enter_text" || kind === "terminal") {
      return hasLiveTerminalSession.value;
    }
    return false;
  }
  return false;
});

function findLatestAgentWorkflowOperation(phaseNames = []) {
  const phases = new Set(
    (Array.isArray(phaseNames) ? phaseNames : [])
      .map((item) => String(item || "").trim())
      .filter(Boolean),
  );
  for (let rowIndex = messages.value.length - 1; rowIndex >= 0; rowIndex -= 1) {
    const row = messages.value[rowIndex];
    if (!row || String(row.role || "") !== "assistant") continue;
    const operations = messageProcessOperations(row);
    for (let opIndex = operations.length - 1; opIndex >= 0; opIndex -= 1) {
      const operation = operations[opIndex];
      if (isLocalLiuAgentBubbleOnlyOperation(operation)) continue;
      const phase = normalizeOperationPhase(
        operation?.phase || operation?.status,
      );
      if (!phases.size || phases.has(phase)) {
        return { row, rowIndex, operation, phase };
      }
    }
  }
  return null;
}

function summarizeAgentWorkflowOperation(operation) {
  if (!operation) return "";
  return clipText(
    [
      String(operation?.summary || "").trim(),
      String(operation?.title || "").trim(),
    ]
      .filter(Boolean)
      .join(" · "),
    72,
  );
}

const agentWorkflowState = computed(() => {
  const queuedCount = queuedFollowupMessages.value.length;
  const waiting = findLatestAgentWorkflowOperation(["waiting_user"]);
  if (waiting) {
    return {
      phase: "waiting_user",
      title: "等待你确认后继续",
      detail:
        summarizeAgentWorkflowOperation(waiting.operation) ||
        "在消息卡片完成确认或授权后，系统会自动继续执行。",
      actionLabel: "查看等待项",
      waitingCount: 1,
      runningCount: 0,
      queuedCount,
    };
  }

  const blocked = findLatestAgentWorkflowOperation(["blocked"]);
  if (blocked) {
    return {
      phase: "blocked",
      title: "执行已阻断",
      detail:
        summarizeAgentWorkflowOperation(blocked.operation) ||
        "当前步骤需要处理阻塞原因后才能继续。",
      actionLabel: "查看阻塞项",
      waitingCount: 0,
      runningCount: 0,
      queuedCount,
    };
  }

  const failed = findLatestAgentWorkflowOperation(["failed"]);
  if (failed && !chatLoading.value && pendingRequests.size === 0) {
    return {
      phase: "failed",
      title: "执行失败",
      detail:
        summarizeAgentWorkflowOperation(failed.operation) ||
        "当前回合有步骤失败，请查看运行轨迹。",
      actionLabel: "查看失败项",
      waitingCount: 0,
      runningCount: 0,
      queuedCount,
    };
  }

  const running = findLatestAgentWorkflowOperation(["running", "pending"]);
  const hasCurrentPendingRequest = hasPendingRequestForChatSession(
    currentChatSessionId.value,
  );
  const isRunning = Boolean(
    running ||
    chatLoading.value ||
    hasCurrentPendingRequest ||
    currentChatSessionLocalLiuAgentRunning.value ||
    currentChatSessionNativeExternalAgentRunning.value ||
    backgroundTerminalCount.value > 0,
  );
  if (isRunning) {
    const isNativeExternalAgentRunning =
      currentChatSessionNativeExternalAgentRunning.value;
    const nativeRunningStatus = isNativeExternalAgentRunning
      ? buildNativeExternalAgentRunningStatus(nativeExternalAgentSession.value || {})
      : null;
    return {
      phase: "running",
      title: isNativeExternalAgentRunning
        ? "Runner 运行中"
        : backgroundTerminalCount.value > 0 && !chatLoading.value
          ? "项目终端运行中"
          : "智能体执行中",
      detail: isNativeExternalAgentRunning
        ? nativeRunningStatus?.summary ||
          nativeExternalAgentSession.value?.summary ||
          "Runner 正在本机工作区执行。"
        : summarizeAgentWorkflowOperation(running?.operation) ||
          (queuedCount
            ? "补充内容已排队，当前步骤结束后会自动合并。"
            : "正在执行工具、命令或等待运行结果。"),
      actionLabel: running || isNativeExternalAgentRunning ? "查看轨迹" : "",
      waitingCount: 0,
      runningCount: 1,
      queuedCount,
    };
  }

  if (queuedCount) {
    return {
      phase: "queued",
      title: "补充已排队",
      detail: "当前回合结束后会自动合并补充内容并重新规划。",
      actionLabel: "",
      waitingCount: 0,
      runningCount: 0,
      queuedCount,
    };
  }

  return {
    phase: "idle",
    title: "",
    detail: "",
    actionLabel: "",
    waitingCount: 0,
    runningCount: 0,
    queuedCount: 0,
  };
});

const showAgentWorkflowStatusStrip = computed(
  () => false,
);

const agentWorkflowMetaItems = computed(() => {
  const state = agentWorkflowState.value;
  const items = [];
  if (state.phase === "running") {
    items.push(workingStatusElapsedLabel.value);
  }
  if (state.waitingCount) {
    items.push(`${state.waitingCount} 个等待项`);
  }
  if (state.runningCount) {
    items.push("执行中");
  }
  if (state.queuedCount) {
    items.push(`已排队 ${state.queuedCount} 条补充`);
  }
  if (state.phase === "blocked") {
    items.push("需要处理阻塞");
  }
  if (state.phase === "failed") {
    items.push("查看失败原因");
  }
  return items;
});

function focusAgentWorkflowOperation() {
  const matched =
    findLatestAgentWorkflowOperation(["waiting_user", "blocked", "failed"]) ||
    findLatestAgentWorkflowOperation(["running", "pending"]);
  if (matched?.row) {
    matched.row.processExpanded = true;
    void focusMessageById(matched.row.id, { smooth: true });
    return true;
  }
  const nativeRow = findNativeExternalAgentMessage(
    normalizeNativeExternalAgentSessionId(nativeExternalAgentSession.value),
  );
  if (nativeRow) {
    nativeRow.processExpanded = true;
    void focusMessageById(nativeRow.id, { smooth: true });
    return true;
  }
  scrollToBottom({ smooth: true });
  return false;
}

const showPauseGenerationButton = computed(
  () =>
    (Boolean(getActiveRequestId()) ||
      currentChatSessionLocalLiuAgentRunning.value ||
      currentChatSessionNativeExternalAgentRunning.value) &&
    (chatLoading.value ||
      currentChatSessionLocalLiuAgentRunning.value ||
      currentChatSessionNativeExternalAgentRunning.value) &&
    !isAwaitingUserInteraction.value &&
    !isTerminalInteractionMode.value,
);

const backgroundTerminalCount = computed(() => {
  if (!String(selectedProjectId.value || "").trim()) return 0;
  return hasLiveTerminalSession.value ? 1 : 0;
});

const currentChatSessionNativeExternalAgentRunning = computed(() =>
  isNativeExternalAgentRunningForChatSession(currentChatSessionId.value),
);

const showWorkingStatusBar = computed(() => {
  if (!String(selectedProjectId.value || "").trim()) return false;
  if (isAwaitingUserInteraction.value) return false;
  return Boolean(
    chatLoading.value ||
    hasPendingRequestForChatSession(currentChatSessionId.value) ||
    currentChatSessionLocalLiuAgentRunning.value ||
    currentChatSessionNativeExternalAgentRunning.value ||
    backgroundTerminalCount.value > 0,
  );
});

const workingStatusElapsedSeconds = computed(() => {
  const startedAt = Number(workingStatusStartedAt.value || 0);
  if (!startedAt) return 0;
  return Math.max(
    0,
    Math.floor(
      (Number(workingStatusNow.value || Date.now()) - startedAt) / 1000,
    ),
  );
});

const workingStatusElapsedLabel = computed(
  () => `(${formatWorkingDuration(workingStatusElapsedSeconds.value)})`,
);

const workingStatusTitle = computed(() => "本地智能体执行中");

const workingStatusMetaItems = computed(() => [
  "本机模型/工具运行中",
  "等待结果返回",
]);

function formatWorkingDuration(totalSeconds) {
  const seconds = Math.max(0, Number(totalSeconds || 0));
  const hours = Math.floor(seconds / 3600);
  const minutes = Math.floor((seconds % 3600) / 60);
  const remainingSeconds = seconds % 60;
  if (hours > 0) {
    return `${hours}h ${String(minutes).padStart(2, "0")}m`;
  }
  if (minutes > 0) {
    return `${minutes}m ${String(remainingSeconds).padStart(2, "0")}s`;
  }
  return `${remainingSeconds}s`;
}

function workingStatusSessionKey(chatSessionId = currentChatSessionId.value) {
  return String(chatSessionId || "").trim() || "__current__";
}

function workingStatusRunKey(
  chatSessionId = currentChatSessionId.value,
  runId = "",
) {
  const sessionKey = workingStatusSessionKey(chatSessionId);
  const normalizedRunId = String(runId || "").trim();
  return normalizedRunId ? `${sessionKey}::${normalizedRunId}` : sessionKey;
}

function workingStatusKeyBelongsToSession(key, chatSessionId = "") {
  const normalizedKey = String(key || "").trim();
  if (!normalizedKey) return false;
  const sessionKey = workingStatusSessionKey(chatSessionId);
  return (
    normalizedKey === sessionKey ||
    normalizedKey.startsWith(`${sessionKey}::`)
  );
}

function clearWorkingStatusStartForChatSession(chatSessionId = "") {
  const sessionKey = workingStatusSessionKey(chatSessionId);
  for (const key of Array.from(workingStatusStartedAtBySession.keys())) {
    if (key === sessionKey || key.startsWith(`${sessionKey}::`)) {
      workingStatusStartedAtBySession.delete(key);
    }
  }
  if (
    workingStatusKeyBelongsToSession(workingStatusActiveKey.value, chatSessionId)
  ) {
    workingStatusActiveKey.value = "";
    workingStatusStartedAt.value = 0;
    workingStatusNow.value = Date.now();
  }
}

function clearWorkingStatusStartForRun(
  runId = "",
  chatSessionId = currentChatSessionId.value,
) {
  const key = workingStatusRunKey(chatSessionId, runId);
  workingStatusStartedAtBySession.delete(key);
  if (workingStatusActiveKey.value === key) {
    workingStatusActiveKey.value = "";
    workingStatusStartedAt.value = 0;
    workingStatusNow.value = Date.now();
  }
}

function startWorkingStatusTimer(
  runId = "",
  chatSessionId = currentChatSessionId.value,
) {
  const explicitRunId = String(runId || "").trim();
  let key = explicitRunId
    ? workingStatusRunKey(chatSessionId, explicitRunId)
    : String(workingStatusActiveKey.value || "").trim();
  if (!key || !workingStatusKeyBelongsToSession(key, chatSessionId)) {
    key = workingStatusRunKey(chatSessionId);
  }
  let startedAt = Number(workingStatusStartedAtBySession.get(key) || 0);
  if (!startedAt) {
    startedAt = Date.now();
    workingStatusStartedAtBySession.set(key, startedAt);
  }
  workingStatusActiveKey.value = key;
  workingStatusStartedAt.value = startedAt;
  workingStatusNow.value = Date.now();
  if (workingStatusTimer !== null) return;
  workingStatusTimer = window.setInterval(() => {
    workingStatusNow.value = Date.now();
  }, 1000);
}

function stopWorkingStatusTimer() {
  if (workingStatusTimer !== null) {
    window.clearInterval(workingStatusTimer);
    workingStatusTimer = null;
  }
  workingStatusActiveKey.value = "";
  workingStatusStartedAt.value = 0;
  workingStatusNow.value = Date.now();
}

function handleWorkingStatusKeydown(event) {
  if (event?.key !== "Escape") return;
  if (!showWorkingStatusBar.value) return;
  if (isAwaitingUserInteraction.value) return;
  event.preventDefault();
  stopGeneration();
}

function canSupersedePendingInteraction(interaction) {
  const operation = interaction?.operation;
  if (!operation) return false;
  const actionType = normalizeOperationActionType(operation?.actionType);
  const kind = String(operation?.kind || "")
    .trim()
    .toLowerCase();
  const meta =
    operation?.meta && typeof operation.meta === "object" ? operation.meta : {};
  if (String(meta.approval_id || meta.review_id || "").trim()) {
    return false;
  }
  if (String(meta.approval_mode || "").trim() === "terminal") {
    return false;
  }
  return (
    ["open_url", "enter_text", "select"].includes(actionType) || kind === "auth"
  );
}

function isInteractionContinuationAck(text) {
  const normalized = String(text || "")
    .trim()
    .replace(/\s+/g, "")
    .toLowerCase();
  return [
    "好了",
    "好啦",
    "已好了",
    "完成了",
    "已完成",
    "授权了",
    "已授权",
    "我已授权",
    "登录好了",
    "登录完成",
    "done",
    "ok",
  ].includes(normalized);
}

function isInteractionContinueIntent(text) {
  const normalized = String(text || "")
    .trim()
    .replace(/\s+/g, "")
    .toLowerCase();
  return [
    "继续",
    "继续执行",
    "继续吧",
    "接着",
    "接着执行",
    "下一步",
    "continue",
    "resume",
  ].includes(normalized);
}

async function submitPendingInteractionAckIfNeeded(text) {
  const interaction = activePendingInteraction.value;
  const normalizedText = String(text || "").trim();
  if (
    !interaction?.operation ||
    (!isInteractionContinuationAck(normalizedText) &&
      !isInteractionContinueIntent(normalizedText))
  ) {
    return false;
  }
  const operation = interaction.operation;
  const schema = operationInteractionSchema(operation);
  if (schema) {
    if (!canSubmitOperationInteraction(operation)) {
      ElMessage.warning("请先完成消息卡片里的必填项");
      resetDraft();
      return true;
    }
    resetDraft();
    await submitOperationInteraction(operation);
    scrollToBottom();
    return true;
  }
  const actionType = normalizeOperationActionType(operation?.actionType);
  const kind = String(operation?.kind || "")
    .trim()
    .toLowerCase();
  if (actionType === "open_url" || kind === "auth") {
    resetDraft();
    if (isInteractionContinueIntent(normalizedText)) {
      const buttons = operationActionButtons(operation);
      if (buttons.length) {
        await handleOperationAction(operation, buttons[0].key);
      } else {
        ElMessage.info("当前授权任务仍在等待处理，请在浏览器完成授权");
      }
    } else {
      ElMessage.info("已收到授权完成提示，系统检测通过后会自动继续");
    }
    scrollToBottom();
    return true;
  }
  if (isInteractionContinueIntent(normalizedText)) {
    ElMessage.warning("当前等待的是确认类操作，请先使用消息卡片里的按钮继续");
    resetDraft();
    return true;
  }
  scrollToBottom();
  return false;
}

function releasePendingInteractionForFollowup(followupText = "") {
  const interaction = activePendingInteraction.value;
  if (!interaction || !canSupersedePendingInteraction(interaction)) {
    return false;
  }
  const requestId = String(interaction.requestId || "").trim();
  const pending = interaction.pending;
  const row = interaction.row;
  const operation = interaction.operation;
  if (!row || !operation) return false;
  const preview = clipText(String(followupText || "").trim(), 80);
  const summary = preview ? `已收到继续指令：${preview}` : "已切换为下一轮继续";
  upsertMessageOperation(row, {
    ...operation,
    summary,
    phase: "completed",
  });
  appendAssistantStatusNote(
    row,
    "> ↻ 已结束当前等待状态，转到下一轮继续处理。",
  );
  if (requestId && pending) {
    pending.followupReleased = true;
    resolvePendingRequest(requestId, pending, row.content || summary);
  }
  return true;
}

const terminalPanelStatusText = computed(() => {
  if (terminalPanelStatus.value === "error") return "异常";
  if (
    terminalMirrorConnected.value &&
    terminalPanelStatus.value === "running"
  ) {
    return "运行中";
  }
  if (terminalMirrorConnected.value) {
    return "待命";
  }
  if (!hasSelectedProject.value) return "未启用";
  if (!canUseHostTerminal.value) return "未配置";
  return "未启动";
});
