  if (
    terminalMirrorConnected.value ||
    terminalPanelStatus.value === "running"
  ) {
    return [
      {
        id: "terminal-running",
        phase: "running",
        title: terminalActiveCommand.value || "项目终端运行中",
        summary:
          hostTerminalWorkspacePath.value ||
          projectWorkspaceResolved.value ||
          "",
