    [employeeId ? `ID=${employeeId}` : "", role ? `角色=${role}` : ""]
      .filter(Boolean)
      .join(" · "),
    skills.length ? `   技能：${skills.join("、")}` : "",
    domains.length ? `   规则领域：${domains.join("、")}` : "",
