}

async function fetchDefaultAiEntryFileContent(projectId) {
  const normalizedProjectId = String(projectId || "").trim();
  if (!normalizedProjectId) return "";
  const data = await api.get("/projects/query-mcp/runtime", {
    params: {
      project_id: normalizedProjectId,
      chat_session_id: String(currentChatSessionId.value || "").trim() || undefined,
    },
  });
  const runtime = data?.runtime && typeof data.runtime === "object" ? data.runtime : {};
  const prompts = Array.isArray(runtime.cli_prompts) ? runtime.cli_prompts : [];
  const desktopPrompt = prompts.find(
    (item) => String(item?.key || "").trim() === "desktop-agent",
  );
  return String(desktopPrompt?.prompt || runtime.cli_prompt || "").trim();
}

async function createDefaultAiEntryFile() {
  const projectId = String(selectedProjectId.value || "").trim();
  if (!projectId) {
    ElMessage.warning("请先选择项目");
    return;
  }
  const workspacePath = String(
    projectWorkspaceDraftNormalized.value || projectWorkspacePath.value || "",
  ).trim();
  if (!workspacePath) {
    ElMessage.warning("请先保存项目工作区");
    return;
  }
  aiEntryFileCreating.value = true;
  try {
    const savedWorkspacePath = String(projectWorkspacePath.value || "").trim();
    if (workspacePath !== savedWorkspacePath) {
      await saveProjectWorkspaceDirectory(workspacePath, {
        silent: true,
        rethrow: true,
      });
    }
    try {
      await readProjectWorkspaceFile(projectId, DEFAULT_AI_ENTRY_FILE);
      await saveProjectAiEntryFile(DEFAULT_AI_ENTRY_FILE);
      ElMessage.success(`${DEFAULT_AI_ENTRY_FILE} 已存在，已设为 AI 入口文件`);
      return;
    } catch (err) {
      const status = Number(err?.response?.status || err?.status || 0);
      if (status && status !== 404) {
        throw err;
      }
    }
    const content = await fetchDefaultAiEntryFileContent(projectId);
    if (!content) {
      throw new Error("统一 MCP 接入提示词为空，无法创建 AIENTRY.md");
    }
    const saved = await saveProjectWorkspaceFile(projectId, {
      path: DEFAULT_AI_ENTRY_FILE,
      content,
    });
    const savedPath = String(saved?.path || DEFAULT_AI_ENTRY_FILE).trim();
    await saveProjectAiEntryFile(savedPath);
    aiEntryFileDraft.value = savedPath;
    ElMessage.success(`${savedPath} 已创建`);
  } catch (err) {
    ElMessage.error(err?.detail || err?.message || "创建 AIENTRY.md 失败");
  } finally {
    aiEntryFileCreating.value = false;
  }
}

/** 保存项目工作区路径配置到服务端，同步更新本地运行时上下文和执行工作区路径 */
async function saveProjectWorkspacePath(workspacePathOverride = null) {
  const projectId = String(selectedProjectId.value || "").trim();
  if (!projectId) {
    ElMessage.warning("请先选择项目");
    return;
  }
  if (
    projectSettingsHydrating.value ||
    projectSettingsHydratedProjectId.value !== projectId
  ) {
    ElMessage.warning("项目对话设置仍在加载，请稍后再保存");
    return;
  }
  const normalizedOverride =
    typeof Event !== "undefined" && workspacePathOverride instanceof Event
      ? null
      : workspacePathOverride;
  const workspacePath = String(
    normalizedOverride ?? workspacePathDraft.value ?? "",
  ).trim();
  workspacePathSaving.value = true;
  try {
    if (!nativeDesktopBridgeAvailable.value) {
      ElMessage.warning("Runner 只支持桌面端 Runner");
      return;
    }
    workspacePathDraft.value = workspacePath;
    clearAutoSaveTimer();
    autoSaveState.value = "saving";
    const payload = buildProjectChatSettingsPayload();
    const data = await saveProjectChatSettingsRequest(projectId, payload);
    projectChatSettings.value = applyLocalConnectorRuntimeSettings(
      data?.settings || payload,
    );
    await fetchProvidersByProject(projectId);
    markAutoSaveSynced();
    autoSaveState.value = "saved";
    autoSaveUpdatedAt.value = new Date().toLocaleTimeString("zh-CN", {
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit",
    });
    externalAgentWarmupKey.value = "";
    externalAgentInfo.value = normalizeExternalAgentInfo({
      ...externalAgentInfo.value,
      ready: false,
      session_id: "",
      thread_id: "",
      workspace_path: workspacePath,
    });
    if (nativeDesktopBridgeAvailable.value) {
      void refreshNativeExecutorStatus();
    }
    ElMessage.success(
      workspacePath
        ? nativeDesktopBridgeAvailable.value
          ? "本机工作区路径已保存"
          : "本机工作区路径已保存"
        : nativeDesktopBridgeAvailable.value
          ? "已清空本机工作区路径"
          : "已清空本机工作区路径",
    );
  } catch (err) {
    autoSaveState.value = "error";
    ElMessage.error(err?.detail || err?.message || "保存工作区路径失败");
  } finally {
    workspacePathSaving.value = false;
  }
}

async function testProjectWorkspacePath() {
  const projectId = String(selectedProjectId.value || "").trim();
  if (!projectId) {
    ElMessage.warning("请先选择项目");
    return;
  }
  if (!nativeDesktopBridgeAvailable.value) {
    ElMessage.warning("Runner 只支持桌面端 Runner");
    return;
  }
  if (!workspacePathDraftNormalized.value && !workspacePathResolved.value) {
    ElMessage.warning("请先填写工作区绝对路径");
    return;
  }
  workspacePathTesting.value = true;
  try {
    if (workspacePathDirty.value || !workspacePathConfigured.value) {
      await saveProjectWorkspacePath();
    }
    if (nativeDesktopBridgeAvailable.value) {
      await refreshNativeExecutorStatus();
      const workspace = nativeExecutorStatus.value?.workspace;
      if (
        workspace?.configured &&
        (!workspace.exists || !workspace.isDirectory)
      ) {
        throw new Error(nativeWorkspaceStatusLabel.value || "工作区不可访问");
      }
      ElMessage.success("工作区可用，桌面端已完成本机路径检查");
      return;
    }
    throw new Error("Runner 只支持桌面端 Runner");
  } catch (err) {
    ElMessage.error(err?.message || "工作区测试失败");
  } finally {
    workspacePathTesting.value = false;
  }
}

async function sendProjectChatRequest({
  projectId,
  activeChatSessionId,
  userMessageId = "",
  assistantMessage,
  assistantIndex,
  finalUserPrompt,
  activeSessionSourceContext,
  attachmentNames = [],
  base64Images = [],
  historyRows = [],
  effectiveAutoUseTools = true,
  effectiveToolPriority = [],
  enabledProjectToolNames = selectedProjectToolNames.value,
  assistAction = null,
  assistToolNames = [],
  onAfterDone = null,
  requestKind = "user_message",
  replaceAssistantContentOnDone = false,
}) {
  const requestId = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  const client = await ensureWsClient(projectId);
  const requestChatMode = "system";
  const requestStartedAt = Date.now();
  applyMessageExecutionTiming(assistantMessage, {
    startedAt: requestStartedAt,
  });
  let pendingState = null;
  const donePromise = new Promise((resolve, reject) => {
    pendingState = {
      resolve,
      reject,
      projectId,
      chatSessionId: activeChatSessionId,
      chatMode: requestChatMode,
      assistantMessageId: String(assistantMessage?.id || "").trim(),
      assistantIndex,
      userPrompt: finalUserPrompt,
      mcpApprovalCancelled: false,
      awaitingTerminalApproval: false,
      handoffTriggered: false,
      projectHostTerminalHandoffTriggered: false,
      lastToolName: "",
      cancelled: false,
      startedAt: requestStartedAt,
    };
    createPendingRequest(requestId, pendingState);
  });
  const employeeIds = normalizeStringList(selectedEmployeeIds.value || []);
  const requestPayload = {
    request_id: requestId,
    message_id: String(userMessageId || "").trim(),
    assistant_message_id: String(assistantMessage?.id || "").trim(),
    chat_session_id: activeChatSessionId,
    request_kind:
      String(requestKind || "user_message").trim() || "user_message",
    chat_mode: requestChatMode,
    chat_surface: chatSurface.value,
    source_context: activeSessionSourceContext,
    external_agent_type: String(
      projectChatSettings.value.external_agent_type ||
        CHAT_SETTINGS_DEFAULTS.external_agent_type,
    ).trim(),
    local_connector_id: String(
      projectChatSettings.value.local_connector_id || "",
    ).trim(),
    connector_workspace_path: localLiuAgentWorkspacePath(),
    connector_sandbox_mode: String(
      projectChatSettings.value.connector_sandbox_mode || "workspace-write",
    ).trim(),
    connector_sandbox_mode_explicit: true,
    skill_resource_directory: String(
      skillResourceDirectoryResolved.value || "",
    ).trim(),
    message: finalUserPrompt,
    employee_ids: employeeIds,
    employee_id: employeeIds.length === 1 ? employeeIds[0] : undefined,
    employee_coordination_mode: String(
      projectChatSettings.value.employee_coordination_mode ||
        CHAT_SETTINGS_DEFAULTS.employee_coordination_mode,
    )
      .trim()
      .toLowerCase(),
    history: historyRows,
    provider_id: selectedProviderId.value || undefined,
    model_name: selectedModelName.value || undefined,
    temperature: Number(temperature.value),
    system_prompt: undefined,
    attachment_names: attachmentNames,
    images: base64Images,
    auto_use_tools: effectiveAutoUseTools,
    tool_priority: effectiveToolPriority,
    history_limit: resolveNumericChatSetting(
      projectChatSettings.value.history_limit,
      CHAT_SETTINGS_DEFAULTS.history_limit,
      { min: 1, max: 50 },
    ),
    answer_style: String(
      projectChatSettings.value.answer_style ||
        CHAT_SETTINGS_DEFAULTS.answer_style,
    ),
    prefer_conclusion_first: Boolean(
      projectChatSettings.value.prefer_conclusion_first ??
      CHAT_SETTINGS_DEFAULTS.prefer_conclusion_first,
    ),
  };
  requestPayload.enabled_project_tool_names = normalizeStringList(
    [
      ...enabledProjectToolNames,
      ...(assistAction?.id === "employee_create" ? assistToolNames : []),
    ],
    200,
  );
  try {
    client.send(requestPayload);
  } catch (err) {
    rejectPendingRequest(requestId, pendingRequests.get(requestId), err);
    if (assistantMessage) {
      assistantMessage.content = `请求失败：${err?.message || "WebSocket 发送失败"}`;
      assistantMessage.time = nowText();
      finishMessageExecutionTiming(assistantMessage);
    }
    throw err;
  }
  await donePromise;
  if (pendingState?.cancelled) {
    return {
      requestId,
      cancelled: true,
    };
  }
  if (replaceAssistantContentOnDone) {
    const row = assistantMessage;
    const finalContent = String(row?.content || "").trim();
    const followupPlanId = String(assistantMessage?.id || "").trim();
    if (row && followupPlanId) {
      upsertMessageOperation(row, {
        operationId: `plan:followup:${followupPlanId}`,
        kind: "plan",
        title: "补充需求",
        summary: finalContent ? "已按补充需求更新结果" : "补充需求处理完成",
        detail: "",
        phase: "completed",
        actionType: "none",
        meta: {
          assistant_message_id: followupPlanId,
        },
      });
    }
  }
  if (
    !String(assistantMessage?.content || "").trim() &&
    !messageOperations(assistantMessage).length
  ) {
    assistantMessage.content = "模型未返回内容。";
  } else if (!String(assistantMessage?.content || "").trim()) {
    assistantMessage.content = "模型未返回最终回答，请检查本轮执行过程。";
  }
  if (typeof onAfterDone === "function") {
    await onAfterDone();
  }
  return {
    requestId,
    cancelled: false,
  };
}

async function sendLocalLiuAgentChatRequest({
  projectId,
  activeChatSessionId,
  userMessage,
  assistantMessage,
  finalUserPrompt,
  historyRows = [],
  displayUserMessageContent = "",
  sourceContext = {},
  attachments = [],
}) {
  const workspacePath = localLiuAgentWorkspacePath();
  if (!hasNativeDesktopBridge()) {
    throw new Error("桌面端本地 liuAgent Runtime 不可用");
  }
  if (!workspacePath) {
    throw new Error("请先配置本机工作区");
  }
  upsertMessageOperation(assistantMessage, {
    operationId: `local-agent:${assistantMessage.id}`,
    kind: "request",
    title: "桌面本地 Agent Runtime",
    summary: "启动桌面本地 Agent Runtime，等待模型计算",
    detail: "",
    phase: "running",
    actionType: "none",
    meta: {
      local_liuagent_operation: "true",
      source: "tauri_liuagent_local_chat",
      chat_session_id: activeChatSessionId,
      cwd: workspacePath,
    },
  });
  appendMessageProcessLog(assistantMessage, {
    text: [
      "本轮目标",
      `  - ${displayUserMessageContent || finalUserPrompt}`,
      `  - 工作区：${workspacePath}`,
      "  - 执行方式：桌面端本地智能体",
    ]
      .filter(Boolean)
      .join("\n"),
    level: "info",
  });
  await upsertProjectChatRequirementRecord({
    chatSessionId: activeChatSessionId,
    status: "in_progress",
    rootGoal: displayUserMessageContent || finalUserPrompt,
    messageId: userMessage.id,
    assistantMessageId: assistantMessage.id,
    source: "desktop_local_agent",
    sourceContext: {
      ...sourceContext,
      runtime: "tauri",
      workspace_path: workspacePath,
    },
  });
  const persistedUserMessage = await persistLocalLiuAgentChatMessage({
    projectId,
    chatSessionId: activeChatSessionId,
    message: userMessage,
    role: "user",
    workspacePath,
    sourceContext,
  });
  if (persistedUserMessage) {
    userMessage.historyPersisted = true;
  }
  const modelRuntime = await buildLocalLiuAgentModelRuntime();
  await saveLocalLiuAgentRuntimeConfigOfflineCache({
    workspacePath,
    providerId: selectedProviderId.value || defaultProviderId.value || "",
    modelRuntime,
  });
  const localChatPayload = {
    projectId,
    chatSessionId: activeChatSessionId,
    messageId: userMessage.id,
    assistantMessageId: assistantMessage.id,
    message: finalUserPrompt,
    workspacePath,
    history: historyRows,
    providerId: selectedProviderId.value || defaultProviderId.value || "",
    modelName: selectedModelName.value || defaultModelName.value || "",
    systemPrompt: buildLocalLiuAgentSystemPrompt(),
    systemPromptParts: buildLocalLiuAgentSystemPromptParts(),
    temperature: Number(temperature.value ?? CHAT_SETTINGS_DEFAULTS.temperature),
    modelRuntime,
    aiEntryFile: String(projectAiEntryFile.value || "").trim(),
    mcpConfig: effectiveMcpConfig.value,
    attachments,
    backendContext: {
      apiBaseUrl: buildLocalLiuAgentBackendApiBaseUrl(),
      token: getStoredToken(),
    },
    permissionDecision: localLiuAgentFullAccessEnabled()
      ? buildLocalLiuAgentPermissionDecision("", {}, { fullAccess: true })
      : null,
  };
  await saveLocalLiuAgentSessionOfflineCache({
    projectId,
    chatSessionId: activeChatSessionId,
    workspacePath,
    status: "in_progress",
    userMessage,
    assistantMessage,
    historyRows,
    rootGoal: displayUserMessageContent || finalUserPrompt,
    modelRuntime,
  });
  const activeRun = {
    chatSessionId: activeChatSessionId,
    projectId,
    assistantMessageId: assistantMessage.id,
    userMessageId: userMessage.id,
    rootGoal: displayUserMessageContent || finalUserPrompt,
    workspacePath,
    cancelled: false,
    startedAt: Date.now(),
  };
  applyLocalLiuAgentRuntimeTiming(assistantMessage, {
    startedAt: activeRun.startedAt,
    running: true,
  });
  setLocalLiuAgentActiveRun(activeChatSessionId, activeRun);
  upsertMessageOperation(assistantMessage, {
    operationId: `local-agent-running:${assistantMessage.id}`,
    kind: "request",
    title: "桌面本地 Agent Runtime",
    summary: "等待本地模型调用事件",
    detail: "模型步骤、工具调用、命令执行、文件读写和授权等待会作为运行轨迹继续追加。",
    phase: "running",
    actionType: "none",
    meta: {
      local_liuagent_operation: "true",
      agent_runtime_event: "true",
      source: "tauri_liuagent_local_chat",
      chat_session_id: activeChatSessionId,
      cwd: workspacePath,
    },
  });
  appendMessageProcessLog(assistantMessage, {
    text: "开始执行\n  - 正在创建本地模型请求\n  - 后续会按“理解目标、规划工具、执行工具、整理结果”展示进度",
    level: "info",
    autoExpand: true,
  });
  assistantMessage.processExpanded = true;
  syncChatLoadingWithCurrentSession();
  let result;
  try {
    await startNativeLiuAgentRuntimeEventSubscription();
    result = await startNativeLiuAgentLocalChat(localChatPayload);
  } catch (err) {
    deleteLocalLiuAgentActiveRun(activeChatSessionId);
    syncChatLoadingWithCurrentSession();
    throw err;
  }
  if (activeRun.cancelled) {
    deleteLocalLiuAgentActiveRun(activeChatSessionId);
    syncChatLoadingWithCurrentSession();
    return { cancelled: true };
  }
  applyLocalLiuAgentRuntimeEvents(assistantMessage, result, {
    chatSessionId: activeChatSessionId,
    workspacePath,
    startedAt: activeRun.startedAt,
  });
  appendLocalLiuAgentStructuredStateOperations(assistantMessage, result, {
    chatSessionId: activeChatSessionId,
    workspacePath,
  });
  const localPermissionRequest = localLiuAgentPermissionRequestFromChatResult(result);
  if (localPermissionRequest) {
    const requestId = String(localPermissionRequest?.requestId || "").trim();
    if (requestId) {
      setLocalLiuAgentPendingPermission(requestId, {
        kind: "local_chat",
        localChatPayload,
        permissionRequest: localPermissionRequest,
        assistantMessageId: assistantMessage.id,
        userMessageId: userMessage.id,
        activeChatSessionId,
        displayUserMessageContent,
        finalUserPrompt,
        sourceContext,
      });
    }
    appendMessageProcessLog(assistantMessage, {
      text: "本机工具执行已暂停，等待你在输入框上方授权",
      level: "warning",
    });
    await persistLocalLiuAgentAssistantState({
      projectId,
      chatSessionId: activeChatSessionId,
      assistantMessage,
      fallbackContent: "本机工具执行已暂停，等待你在输入框上方授权。",
      workspacePath,
      sourceContext: {
        ...sourceContext,
        runtime: "tauri",
        workspace_path: workspacePath,
        permission_request_id: requestId,
        ...localLiuAgentRuntimeTimingSourceContext(assistantMessage),
      },
    });
    await upsertProjectChatRequirementRecord({
      chatSessionId: activeChatSessionId,
      status: "waiting_approval",
      rootGoal: displayUserMessageContent || finalUserPrompt,
      messageId: userMessage.id,
      assistantMessageId: assistantMessage.id,
      resultSummary: assistantMessage.content,
      verificationResult: "本地工具调用已在 executor 执行前暂停，等待用户授权。",
      source: "desktop_local_agent",
      sourceContext: {
        ...sourceContext,
        runtime: "tauri",
        workspace_path: workspacePath,
        permission_request_id: requestId,
        ...localLiuAgentRuntimeTimingSourceContext(assistantMessage),
      },
    });
    await syncLocalLiuAgentRuntimeOutbox({
      projectId,
      chatSessionId: activeChatSessionId,
      workspacePath,
      rootGoal: displayUserMessageContent || finalUserPrompt,
      messageId: userMessage.id,
      assistantMessageId: assistantMessage.id,
    });
    await saveLocalLiuAgentSessionOfflineCache({
      projectId,
      chatSessionId: activeChatSessionId,
      workspacePath,
      status: "waiting_approval",
      userMessage,
      assistantMessage,
      historyRows,
      rootGoal: displayUserMessageContent || finalUserPrompt,
      modelRuntime,
      result,
    });
    deleteLocalLiuAgentActiveRun(activeChatSessionId);
    syncChatLoadingWithCurrentSession();
    return result;
  }
  const ok = Boolean(result?.ok);
  const assistantReasoningContent = String(
    result?.assistantReasoningContent || result?.assistant_reasoning_content || "",
  ).trim();
  if (assistantReasoningContent) {
    assistantMessage.reasoningContent = assistantReasoningContent;
  }
  assistantMessage.content = String(
    result?.assistantContent || result?.assistant_content || result?.summary || "",
  ).trim();
  if (!assistantMessage.content && ok) {
    assistantMessage.content = "本地智能体未返回最终回答，请检查本轮执行过程。";
  }
  if (!assistantMessage.content && !ok) {
    assistantMessage.content = `执行失败：${String(result?.error || "桌面端本地对话失败").trim()}`;
  }
  if (!ok) {
    const runtimeError = String(
      result?.error || result?.summary || assistantMessage.content || "桌面端本地对话失败",
    ).trim();
    showManualCloseErrorDialog(
      runtimeError.includes("model gateway returned HTTP")
        ? "模型网关请求失败"
        : "桌面本地 Agent Runtime 失败",
      runtimeError,
      [
        `providerId=${String(localChatPayload?.providerId || "-").trim() || "-"}`,
        `modelName=${String(localChatPayload?.modelName || "-").trim() || "-"}`,
        `workspacePath=${workspacePath || "-"}`,
        runtimeError,
      ].join("\n"),
    );
  }
  assistantMessage.time = nowText();
  updateLocalLiuAgentRuntimeTimingFromResult(assistantMessage, result, {
    startedAt: activeRun.startedAt,
    endedAt: Date.now(),
  });
  const operations = Array.isArray(result?.operations) ? result.operations : [];
  for (const operation of operations) {
    upsertMessageOperation(
      assistantMessage,
      markLocalLiuAgentBubbleOnlyOperation(operation, {
        chatSessionId: activeChatSessionId,
        workspacePath,
      }),
    );
  }
  upsertMessageOperation(assistantMessage, {
    operationId: `local-agent:${assistantMessage.id}`,
    kind: "request",
    title: "桌面本地 Agent Runtime",
    summary: ok ? "本地会话完成" : "本地会话失败",
    detail: String(result?.error || "").trim(),
    phase: ok ? "completed" : "failed",
    actionType: "none",
    meta: {
      local_liuagent_operation: "true",
      source: "tauri_liuagent_local_chat",
      chat_session_id: activeChatSessionId,
      session_id: String(result?.sessionId || result?.session_id || "").trim(),
      requirement_record_path: String(
        result?.requirementRecordPath || result?.requirement_record_path || "",
      ).trim(),
      cwd: workspacePath,
    },
  });
  appendMessageProcessLog(assistantMessage, {
    text: ok ? "本地对话已完成并写入 workspace requirement 记录" : "本地对话执行失败",
    level: ok ? "success" : "error",
    autoExpand: !ok,
  });
  collapseMessageProcessAfterFinalAnswer(assistantMessage);
  deleteLocalLiuAgentActiveRun(activeChatSessionId);
  syncChatLoadingWithCurrentSession();
  scrollToBottom();
  void (async () => {
    try {
      await persistLocalLiuAgentFinalMessages({
        projectId,
        chatSessionId: activeChatSessionId,
        userMessage,
        assistantMessage,
        workspacePath,
        sourceContext,
        persistUser: false,
      });
      await upsertProjectChatRequirementRecord({
        chatSessionId: activeChatSessionId,
        status: ok ? "done" : "blocked",
        rootGoal: displayUserMessageContent || finalUserPrompt,
        messageId: userMessage.id,
        assistantMessageId: assistantMessage.id,
        resultSummary: assistantMessage.content,
        verificationResult: ok
          ? "桌面端 Tauri 本地 runtime 已返回 assistant 内容，并写入 workspace requirement 记录。"
          : String(result?.error || "桌面端本地 runtime 执行失败。"),
        source: "desktop_local_agent",
        sourceContext: {
          ...sourceContext,
          runtime: "tauri",
          workspace_path: workspacePath,
          requirement_record_path: String(
            result?.requirementRecordPath || result?.requirement_record_path || "",
          ).trim(),
          ...localLiuAgentRuntimeTimingSourceContext(assistantMessage),
        },
      });
      await syncLocalLiuAgentRuntimeOutbox({
        projectId,
        chatSessionId: activeChatSessionId,
        workspacePath,
        rootGoal: displayUserMessageContent || finalUserPrompt,
        messageId: userMessage.id,
        assistantMessageId: assistantMessage.id,
      });
      await saveLocalLiuAgentSessionOfflineCache({
        projectId,
        chatSessionId: activeChatSessionId,
        workspacePath,
        status: ok ? "done" : "blocked",
        userMessage,
        assistantMessage,
        historyRows,
        rootGoal: displayUserMessageContent || finalUserPrompt,
        modelRuntime,
        result,
      });
    } catch (error) {
      console.warn("persist completed local liuAgent turn failed", error);
    }
  })();
  return result;
}

async function fetchLocalLiuAgentDesktopModelRuntime(providerId) {
  const normalizedProviderId = String(providerId || "").trim();
  if (!normalizedProviderId) {
    throw new Error("请先在对话设置中选择本地运行使用的模型供应商");
  }
  const data = await api.get(
    `/llm/providers/${encodeURIComponent(normalizedProviderId)}/desktop-runtime`,
  );
  const runtime =
    data?.runtime && typeof data.runtime === "object" ? data.runtime : {};
  const baseUrl = String(runtime.base_url || runtime.baseUrl || "").trim();
  const apiKey = String(runtime.api_key || runtime.apiKey || "").trim();
  if (!baseUrl || !apiKey) {
    throw new Error("当前模型供应商缺少 Base URL 或 API Key，桌面端无法本地调用模型");
  }
  return runtime;
}

async function buildLocalLiuAgentModelRuntime() {
  const providerId = String(
    selectedProviderId.value || defaultProviderId.value || "",
  ).trim();
  const modelName = String(
    selectedModelName.value || defaultModelName.value || "",
  ).trim();
  const runtime = await fetchLocalLiuAgentDesktopModelRuntime(providerId);
  const resolvedModelName = String(
    modelName ||
      runtime.model_name ||
      runtime.modelName ||
      runtime.default_model ||
      runtime.defaultModel ||
      "",
  ).trim();
  if (!resolvedModelName) {
    throw new Error(
      [
        "当前模型供应商没有可用模型名，已停止发送模型网关请求。",
        `providerId=${providerId || "-"}`,
        `selectedModel=${modelName || "-"}`,
        `runtimeDefaultModel=${String(runtime.default_model || runtime.defaultModel || "-").trim() || "-"}`,
      ].join("\n"),
    );
  }
  return {
    mode: "direct-openai-compatible",
    providerId,
    modelName: resolvedModelName,
    baseUrl: String(runtime.base_url || runtime.baseUrl || "").trim(),
    apiKey: String(runtime.api_key || runtime.apiKey || "").trim(),
    temperature: Number(temperature.value ?? CHAT_SETTINGS_DEFAULTS.temperature),
  };
}

function resolvePendingRequestFast(requestId, pending, content = "") {
  if (!pending || !requestId) return;
  finishMessageExecutionTiming(resolvePendingRequestRow(pending));
  const { chatSessionId } = cleanupRequest(requestId, pending);
  if (!hasPendingRequestForChatSession(chatSessionId)) {
    clearWorkingStatusStartForChatSession(chatSessionId);
  }
  syncChatLoadingWithCurrentSession();
  persistRememberedChatSessionMessages(
    pending.projectId,
    chatSessionId,
  );
  settlePending(pending, "resolve", String(content || "").trim());
}

function cancelPendingChatRequestFast(requestId, pending) {
  if (!pending || !requestId) return false;
  pending.cancelled = true;
  const row = resolvePendingRequestRow(pending);
  const message = "已停止生成。";
  queuedFollowupMessages.value = [];
  activeFollowupAssistantMessageId = "";
  if (row) {
    row.displayMode = "";
    row.content = String(row.content || "").trim() || message;
    row.time = nowText();
    finishMessageExecutionTiming(row);
    completeFinishedMessageOperations(row, message);
    closeOpenAgentRuntimeOperationsForCompletedTurn(row, message);
    upsertMessageOperation(row, {
      operationId: `request:${requestId}`,
      kind: "request",
      title: "本轮执行",
      summary: message,
      detail: "",
      phase: "completed",
      actionType: "none",
      meta: {
        request_id: requestId,
        cancelled: true,
      },
    });
    appendMessageProcessLog(row, {
      level: "info",
      text: message,
      autoExpand: false,
    });
    collapseMessageProcessAfterFinalAnswer(row);
  }
  clearActiveExecutionTransportState(pending?.assistantIndex ?? -1);
  resolvePendingRequestFast(requestId, pending, row?.content || message);
  scrollToBottom();
  return true;
}

function showManualCloseErrorDialog(title, message, detail = "") {
  const normalizedTitle = String(title || "请求失败").trim();
  const normalizedMessage = String(message || "操作失败").trim();
  const normalizedDetail = String(detail || "").trim();
  void ElMessageBox.alert(
    h("div", { class: "manual-close-error-dialog" }, [
      h("p", { style: "margin:0 0 10px;font-weight:600;" }, normalizedMessage),
      normalizedDetail
        ? h(
            "pre",
            {
              style:
                "max-height:360px;overflow:auto;margin:0;padding:10px;border-radius:6px;background:#0f172a;color:#e2e8f0;white-space:pre-wrap;word-break:break-word;font-size:12px;line-height:1.55;",
            },
            normalizedDetail,
          )
        : null,
    ]),
    normalizedTitle,
    {
      type: "error",
      showClose: true,
      showConfirmButton: false,
      closeOnClickModal: false,
      closeOnPressEscape: false,
      customClass: "manual-close-error-message-box",
    },
  );
}

function sendCancelRequestNow(requestId) {
  const normalizedRequestId = String(requestId || "").trim();
  if (!normalizedRequestId) return false;
  const activeClient = wsClient.value;
  if (!activeClient || !activeClient.isOpen()) return false;
  try {
    activeClient.send({ type: "cancel", request_id: normalizedRequestId });
    return true;
  } catch (err) {
    console.warn("send cancel request failed", err);
    return false;
  }
}

function sendCancelRequestInBackground(requestId) {
  const normalizedRequestId = String(requestId || "").trim();
  if (!normalizedRequestId) return;
  window.setTimeout(() => {
    sendCancelRequestNow(normalizedRequestId);
  }, 0);
}

async function cancelActiveLocalLiuAgentRun() {
  const chatSessionId = String(currentChatSessionId.value || "").trim();
  const run = localLiuAgentActiveRunForChatSession(chatSessionId);
  if (!run || run.cancelled) return false;
  run.cancelled = true;
  deleteLocalLiuAgentActiveRun(chatSessionId);
  await clearLocalLiuAgentPendingPermissionsForChatSession(chatSessionId);
  const row = localLiuAgentActiveRunRow(run);
  const message = "已停止本地智能体执行。";
  if (row) {
    row.displayMode = "";
    row.content = String(row.content || "").trim() || message;
    row.time = nowText();
    applyLocalLiuAgentRuntimeTiming(row, {
      startedAt: run.startedAt,
      endedAt: Date.now(),
    });
    completeFinishedMessageOperations(row, message);
    closeOpenAgentRuntimeOperationsForCompletedTurn(row, message);
    upsertMessageOperation(row, {
      operationId: `local-agent-cancelled:${row.id}`,
      kind: "request",
      title: "本轮任务已取消",
      summary: message,
      detail: "前端已停止等待本轮本地运行结果；底层 Tauri 任务可能仍会短暂收尾，返回后不会覆盖当前消息。",
      phase: "completed",
      actionType: "none",
      meta: {
        local_liuagent_operation: "true",
        source: "tauri_liuagent_local_chat",
        chat_session_id: chatSessionId,
        cwd: String(run.workspacePath || "").trim(),
        cancelled: true,
        terminal_task: true,
        resumable: false,
      },
    });
    appendMessageProcessLog(row, {
      level: "warning",
      text: message,
      autoExpand: true,
    });
    row.processExpanded = true;
    await persistLocalLiuAgentAssistantState({
      projectId: run.projectId || selectedProjectId.value,
      chatSessionId,
      assistantMessage: row,
      fallbackContent: message,
      workspacePath: String(run.workspacePath || "").trim(),
      sourceContext: {
        chat_mode: "system",
        surface: chatSurface.value,
        runtime: "tauri",
        workspace_path: String(run.workspacePath || "").trim(),
        cancelled: true,
        ...localLiuAgentRuntimeTimingSourceContext(row),
      },
    });
    void upsertProjectChatRequirementRecord({
      chatSessionId,
      status: "cancelled",
      rootGoal:
        String(run.rootGoal || "").trim() ||
        String(row.content || "").trim() ||
        message,
      messageId: String(run.userMessageId || "").trim(),
      assistantMessageId: row.id,
      resultSummary: row.content,
      verificationResult: message,
      source: "desktop_local_agent",
      sourceContext: {
        runtime: "tauri",
        workspace_path: String(run.workspacePath || "").trim(),
        cancelled: true,
        ...localLiuAgentRuntimeTimingSourceContext(row),
      },
    });
  }
  queuedFollowupMessages.value = [];
  activeFollowupAssistantMessageId = "";
  clearWorkingStatusStartForChatSession(chatSessionId);
  syncChatLoadingWithCurrentSession();
  chatLoading.value = isChatSessionBusy();
  scrollToBottom();
  return true;
}

function closeIdleChatWsAfterFastCancel() {
  if (queuedFollowupMessages.value.length > 0) return;
  if (!wsClient.value || pendingRequests.size > 0) return;
  wsClient.value.close(1000, "generation cancelled");
  terminalMirrorConnected.value = false;
  wsClient.value = null;
  wsConnected.value = false;
  wsProjectId.value = "";
}

async function stopGeneration() {
  if (await cancelActiveLocalLiuAgentRun()) {
    ElMessage.info("已停止本地智能体执行");
    return;
  }
  if (await clearLocalLiuAgentPendingPermissionsForChatSession()) {
    ElMessage.info("已取消待授权操作");
    return;
  }
  const currentRequestId = getActiveRequestId();
  if (currentRequestId) {
    const pending = pendingRequests.get(currentRequestId);
    if (cancelPendingChatRequestFast(currentRequestId, pending)) {
      sendCancelRequestNow(currentRequestId);
      closeIdleChatWsAfterFastCancel();
      ElMessage.info("已停止生成");
      return;
    }
    sendCancelRequestInBackground(currentRequestId);
    ElMessage.info("已发送停止指令");
    return;
  }
  if (currentChatSessionNativeExternalAgentRunning.value) {
    if (cancelActiveNativeExternalAgentSession()) {
      return;
    }
  }
  const now = Date.now();
  if (now - lastNoActiveGenerationWarningAt < 1200) return;
  lastNoActiveGenerationWarningAt = now;
  ElMessage.warning("当前没有可暂停的生成任务");
}

async function generateEmployeeDraftWithoutProject() {
  const text = String(draftText.value || "").trim();
  if (!text) {
    ElMessage.warning("请先描述你要创建的员工");
    return;
  }
  const userMessage = {
    id: createLocalMessageId(),
    role: "user",
    content: text,
    images: [],
    videos: [],
    attachments: [],
    time: nowText(),
  };
  const assistantMessage = {
    id: createLocalMessageId(),
    role: "assistant",
    content: "",
    images: [],
    videos: [],
    attachments: [],
    displayMode: "",
    terminalLog: [],
    processExpanded: false,
    audit: null,
    taskTreeAudit: null,
    processLog: [],
    statusNotes: [],
    operations: [],
    time: nowText(),
  };

  const history = messages.value
    .slice(-6)
    .map((item) => ({
      role: String(item?.role || "assistant"),
      content: String(item?.content || ""),
    }))
    .filter(
      (item) =>
        ["user", "assistant"].includes(item.role) && item.content.trim(),
    );

  messages.value.push(userMessage);
  messages.value.push(assistantMessage);
  activeComposerPlan.value = null;
  activeComposerPlanOwnerId.value = assistantMessage.id;
  composerPlanExpanded.value = true;
  applyMessageExecutionTiming(assistantMessage, { startedAt: Date.now() });

  const assistantIndex = messages.value.length - 1;
  chatLoading.value = true;
  startWorkingStatusTimer(assistantMessage.id);
  resetDraft();
  scrollToBottom();

  try {
    await ensureEmployeeDraftCatalog();
    const response = await generateEmployeeDraft({
      message: String(
        [text, "", buildEmployeeDraftAssistContext()]
          .filter(Boolean)
          .join("\n"),
      ),
      history,
      provider_id: String(
        selectedProviderId.value || defaultProviderId.value || "",
      ).trim(),
      model_name: String(
        selectedModelName.value || defaultModelName.value || "",
      ).trim(),
      temperature: Number(
        temperature.value ?? CHAT_SETTINGS_DEFAULTS.temperature,
      ),
      system_prompt:
        "你是 AI 员工架构师。请根据用户需求和现有技能、规则目录生成员工草稿。先给一句简短说明，最后必须附带严格 JSON 的 ```employee-draft``` 代码块；如果能明确整理出可直接落地的员工规则，请输出 rule_drafts 数组，每项包含 title、domain、content。",
    });
    messages.value[assistantIndex].content = String(
      response?.content || "未生成员工草稿。",
    ).trim();
    await autoCreateEmployeeFromDraftMessage(messages.value[assistantIndex], {
      resetAssist: true,
    });
  } catch (err) {
    messages.value[assistantIndex].content =
      `请求失败：${err?.message || "未知错误"}`;
    ElMessage.error(err?.detail || err?.message || "生成员工草稿失败");
  } finally {
    finishMessageExecutionTiming(messages.value[assistantIndex]);
    chatLoading.value = false;
    scrollToBottom();
  }
}

