  };
  const assistantMessage = {
    id: createLocalMessageId(),
    role: "assistant",
    content: "",
    images: [],
    videos: [],
    attachments: [],
    displayMode: "",
    terminalLog: [],
    processExpanded: false,
    audit: null,
    taskTreeAudit: null,
    processLog: [],
    statusNotes: [],
    operations: [],
